nodes.description:
async function craftCraftingTable(bot, count = 1, plankVariant = "birch_planks") {
    // This function crafts a specified number of crafting tables by validating inputs and ensuring there are four planks per table of the requested plank variant; it checks the inventory for existing planks and, if insufficient, produces the missing planks using a preferred specialized crafting routine when available or a fallback crafting attempt while waiting for inventory synchronization, then performs the 2x2 craft to create the requested number of crafting tables, returns the total crafting tables now present in inventory, and on failure reports or rethrows the encountered error.
}

nodes.code:
async function craftCraftingTable(bot, count = 1, plankVariant = "birch_planks") {
  // Local helpers to keep this function self-contained
  const mcData = require("minecraft-data")(bot.version);

  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter((it) => it && it.name === name)
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Small utility to wait for inventory sync if available
  async function waitForSync(ticks = 4) {
    if (typeof waitForInventorySync === "function") {
      await waitForInventorySync(bot, ticks);
    } else if (typeof bot.waitForTicks === "function") {
      await bot.waitForTicks(ticks);
    } else {
      // best-effort no-op if none available
      await new Promise((res) => setTimeout(res, 50 * ticks));
    }
  }

  // Parameter validation
  if (typeof count !== "number" || count <= 0) {
    throw new Error("count must be a positive number");
  }
  if (typeof plankVariant !== "string") {
    throw new Error("plankVariant must be a string (e.g., 'birch_planks')");
  }
  if (!mcData.itemsByName[plankVariant]) {
    throw new Error(`Unknown plank item: ${plankVariant}`);
  }
  if (!mcData.itemsByName["crafting_table"]) {
    throw new Error("mcData does not contain crafting_table (unexpected)");
  }

  const planksNeededTotal = count * 4;

  try {
    bot.chat(`I will craft ${count} crafting_table(s). Need ${planksNeededTotal} ${plankVariant}.`);

    const havePlanks = getItemCount(plankVariant);
    if (havePlanks >= planksNeededTotal) {
      bot.chat(`I already have ${havePlanks} ${plankVariant}. No need to craft planks.`);
    } else {
      const missingPlanks = planksNeededTotal - havePlanks;
      bot.chat(`I have ${havePlanks} ${plankVariant}. Crafting ${missingPlanks} more...`);

      // Prefer robust specialized skill if available
      let afterPlanks;
      if (typeof craftBirchPlanks === "function") {
        // craftBirchPlanks accepts (bot, targetPlanks, plankVariantOrOptions...)
        // we ask it to produce a DELTA by passing interpretAsDelta: true
        afterPlanks = await craftBirchPlanks(bot, missingPlanks, { interpretAsDelta: true, plankVariant });
      } else {
        // Fallback: attempt simple craftItem + sync
        await craftItem(bot, plankVariant, missingPlanks);
        await waitForSync();
        afterPlanks = getItemCount(plankVariant);
      }

      bot.chat(`Now have ${afterPlanks} ${plankVariant}.`);
      if (afterPlanks < planksNeededTotal) {
        throw new Error(`Failed to obtain enough ${plankVariant}. Have ${afterPlanks}, need ${planksNeededTotal}.`);
      }
    }

    // Now craft the crafting table(s). 2x2 recipe, no placed crafting required.
    bot.chat(`Crafting ${count} crafting_table(s) now...`);
    await craftItem(bot, "crafting_table", count);
    await waitForSync();

    const craftedTables = getItemCount("crafting_table");
    bot.chat(`Done. I now have ${craftedTables} crafting_table(s) in my inventory.`);
    return craftedTables;
  } catch (err) {
    // Attempt to use shared reporter if present, otherwise log and rethrow
    if (typeof reportErrorAndRethrow === "function") {
      await reportErrorAndRethrow(bot, err, "Failed to craft crafting_table");
    } else {
      try {
        bot.chat(`Failed to craft crafting_table: ${err.message}`);
      } catch (e) {
        // swallow chat errors
      }
      throw err;
    }
  }
}

function getMcDataForBot(bot) {
  // Self-contained helper to obtain minecraft-data for the bot's version.
  // Validates the bot and version are present and returns the mcData object.
  if (!bot) {
    throw new Error("getMcDataForBot: bot is undefined");
  }
  if (!bot.version) {
    throw new Error("getMcDataForBot: bot.version is undefined");
  }
  // Require locally inside the function so this skill is self-contained.
  const mcData = require("minecraft-data")(bot.version);
  if (!mcData) {
    throw new Error(`getMcDataForBot: failed to load minecraft-data for version ${bot.version}`);
  }
  return mcData;
}

nodes.description:
async function setupCraftingTable(bot, maxDistance = 6) {
    // This async routine ensures a usable crafting table near the bot: it first looks for an already-placed crafting table within maxDistance and returns its position if found; if none is found it verifies the bot is alive, checks inventory for a crafting_table item and attempts to craft one if missing while honoring an options.allowConsumeInventory flag (default false) so it will not consume inventory unless explicitly allowed; it then searches for a valid nearby placement position (air/replaceable, not occupying the bot's feet or head, adjacent to at least one solid block) and, if a position is found and consumption is permitted, places a crafting table from inventory and returns an object describing the placement, otherwise it returns null if consumption is disallowed or throws an error if the bot/entity is missing or no valid placement exists or placement/crafting fails.
}

nodes.code:
async function setupCraftingTable(bot, maxDistance = 6) {
  // CRITICAL: declare mcData and Vec3 at the very beginning
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Support an options object passed as the 2nd or 3rd argument without changing the signature.
  // Default is conservative: do NOT consume an inventory crafting_table unless explicitly allowed.
  let options = { allowConsumeInventory: false };
  if (typeof maxDistance === "object" && maxDistance !== null) {
    options = Object.assign(options, maxDistance);
    maxDistance = 6;
  } else {
    const third = arguments[2];
    if (third && typeof third === "object") {
      options = Object.assign(options, third);
    }
  }

  // Helper: safe inventory check for an item name -> total count
  function getItemCountByName(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter((it) => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Helper: check whether a block position is a valid place target
  function isValidPlacementPos(pos) {
    // pos is Vec3
    const block = bot.blockAt(pos);
    // Treat null chunk as invalid
    if (!block) return false;

    // Must be air or replaceable. We'll accept explicit 'air' or common replaceables.
    const replaceables = new Set([
      "air",
      "cave_air",
      "void_air",
      "tall_grass",
      "fern",
      "dead_bush",
      "grass",
      "seagrass",
      "water",
      "flowing_water",
    ]);
    if (!(block.name && replaceables.has(block.name))) {
      return false;
    }

    // Must not be the bot's foot or head block
    if (bot.entity) {
      const foot = bot.entity.position.floored();
      const head = foot.offset(0, 1, 0);
      if (pos.equals(foot) || pos.equals(head)) return false;
    }

    // At least one adjacent block must be solid (boundingBox === 'block')
    const neighbors = [
      pos.offset(1, 0, 0),
      pos.offset(-1, 0, 0),
      pos.offset(0, 1, 0),
      pos.offset(0, -1, 0),
      pos.offset(0, 0, 1),
      pos.offset(0, 0, -1),
    ];
    for (const nPos of neighbors) {
      const nBlock = bot.blockAt(nPos);
      if (nBlock && nBlock.boundingBox === "block") return true;
    }
    return false;
  }

  // Helper: find a nearby valid placement position within maxDistance (returns Vec3 or null)
  function findNearbyPlacement(bot, maxDistance) {
    if (!bot.entity) return null;
    const foot = bot.entity.position.floored();
    // Search by expanding radius (prefer close positions)
    for (let r = 1; r <= maxDistance; r++) {
      for (let dx = -r; dx <= r; dx++) {
        for (let dy = -1; dy <= 2; dy++) {
          for (let dz = -r; dz <= r; dz++) {
            // Only examine the shell at radius r to prioritize near positions
            if (Math.max(Math.abs(dx), Math.abs(dz)) !== r) continue;
            const pos = foot.offset(dx, dy, dz);
            if (isValidPlacementPos(pos)) return pos;
          }
        }
      }
    }
    return null;
  }

  // Begin main logic
  if (!bot) throw new Error("Bot is required");
  if (!bot.entity) {
    if (bot.chat) {
      bot.chat("I seem to be dead or disconnected (bot.entity undefined). Cannot place crafting table right now.");
    }
    throw new Error("bot.entity undefined");
  }

  // Precondition: prefer an already-placed crafting table. Avoid consuming inventory or crafting if a placed one exists.
  const existing = bot.findBlock({
    matching: mcData.blocksByName.crafting_table.id,
    maxDistance,
  });
  if (existing) {
    if (bot.chat) {
      bot.chat(
        `Found an existing crafting table at ${existing.position.x}, ${existing.position.y}, ${existing.position.z}.`,
      );
    }
    return existing.position;
  }

  if (bot.chat) {
    bot.chat("No placed crafting table found nearby.");
  }

  // Ensure we have a crafting_table item; if not, craft one (craft only when no placed table exists)
  let craftingTableCount = getItemCountByName("crafting_table");
  if (craftingTableCount <= 0) {
    if (bot.chat) {
      bot.chat("I don't have a crafting table item. Crafting one now...");
    }
    try {
      // craftCraftingTable is an available skill
      await craftCraftingTable(bot, 1);
      await waitForInventorySync(bot);
      craftingTableCount = getItemCountByName("crafting_table");
    } catch (err) {
      await reportErrorAndRethrow(bot, err, "Failed to craft a crafting table");
    }
  } else {
    if (bot.chat) {
      bot.chat("I have a crafting table in inventory.");
    }
  }

  // If we have an inventory crafting_table but caller disallows consuming inventory, do NOT place it.
  if (craftingTableCount > 0 && !options.allowConsumeInventory) {
    if (bot.chat) {
      bot.chat(
        "I will not consume a crafting_table from inventory because allowConsumeInventory=false. No table placed.",
      );
    }
    return null;
  }

  // Find placement position and place the crafting table (this will consume one crafting_table from inventory)
  const placePos = findNearbyPlacement(bot, maxDistance);
  if (!placePos) {
    if (bot.chat) {
      bot.chat(
        `No valid placement position found within ${maxDistance} blocks. Try moving to a different spot or increase maxDistance.`,
      );
    }
    throw new Error(`No valid placement position within ${maxDistance} blocks`);
  }

  if (bot.chat) {
    bot.chat(`Consuming 1 crafting_table from inventory to place at ${placePos.x}, ${placePos.y}, ${placePos.z}...`);
  }

  try {
    // placeItem is an available primitive that equips and places the given item
    await placeItem(bot, "crafting_table", placePos);
    if (bot.chat) {
      bot.chat(`Placed a crafting table at ${placePos.x}, ${placePos.y}, ${placePos.z}.`);
    }
    return {
      placed: true,
      position: placePos,
      consumedInventory: true,
    };
  } catch (err) {
    await reportErrorAndRethrow(bot, err, "Failed to place crafting table");
  }
}

async function reportErrorAndRethrow(bot, err, prefixMessage = '') {
  // Self-contained helper to chat an error message (if possible) and rethrow the original error.
  // Parameters:
  // - bot: bot object (expected to have chat function)
  // - err: Error (or any value) to rethrow
  // - prefixMessage: optional string prefix for the chat message (e.g., 'Failed to craft')

  // Normalize error message
  const errMsg = (err && (typeof err.message === 'string')) ? err.message : String(err);
  const msg = prefixMessage ? `${prefixMessage}: ${errMsg}` : errMsg;

  // Try to send a chat message about the error. If chat fails, swallow that error
  // but still rethrow the original error afterwards.
  try {
    if (bot && typeof bot.chat === 'function') {
      // Use try/catch to avoid any exceptions from chat disrupting rethrow
      bot.chat(msg);
    }
  } catch (chatErr) {
    // ignore chat errors
  }

  // Always rethrow the original error so callers receive the same failure
  throw err;
}

