}

nodes.code:
async function ensureCobblestone(bot, targetTotal = 3, maxAttempts = 3) {
  // Wrapper for cobblestone-specific defaults
  return ensureResource(bot, 'cobblestone', targetTotal, maxAttempts);
}

async function ensureResource(bot, resourceType, targetTotal = 1, maxAttempts = 3, exploreTime = 60) {
  // Generic ensureer for several resource types (cobblestone, logs, wood_logs)
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  if (!bot) throw new Error("Bot instance is required");
  if (!bot.entity) {
    bot.chat("I seem to be dead or disconnected. Cannot ensure resource right now.");
    throw new Error("bot.entity undefined");
  }

  // Inventory helpers
  function getItemCountByName(itemName) {
    return bot.inventory.items()
      .filter(it => it && it.name === itemName)
      .reduce((sum, it) => sum + it.count, 0);
  }
  function countLogsInInventory() {
    return bot.inventory.items()
      .filter(it => it && typeof it.name === "string" && it.name.endsWith("_log"))
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Block-finding helpers (used for logs)
  function findNearbyLogBlock(maxDistance = 32) {
    return bot.findBlock({
      matching: (b) => !!b && typeof b.name === "string" && b.name.endsWith("_log"),
      maxDistance: maxDistance,
    });
  }
  function randomHorizontalDirection() {
    const options = [
      new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1),
      new Vec3(1, 0, 1), new Vec3(-1, 0, 1), new Vec3(1, 0, -1), new Vec3(-1, 0, -1),
    ];
    return options[Math.floor(Math.random() * options.length)];
  }

  // Determine counting strategy based on resourceType
  function getCurrentCount() {
    if (resourceType === "cobblestone") return getItemCountByName("cobblestone");
    if (resourceType === "logs" || resourceType === "wood_logs") return countLogsInInventory();
    // default fallback: try to count items whose name equals resourceType
    return getItemCountByName(String(resourceType));
  }

  // Start
  bot.chat && bot.chat(`Ensuring I have ${targetTotal} of ${resourceType}...`);

  let current = getCurrentCount();
  if (current >= targetTotal) {
    bot.chat && bot.chat(`Already have ${current}/${targetTotal} ${resourceType}.`);
    return current;
  }

  let attempts = 0;
  while (attempts < maxAttempts && current < targetTotal) {
    attempts++;
    const need = targetTotal - current;
    bot.chat && bot.chat(`Attempt ${attempts}/${maxAttempts}: need ${need} more ${resourceType}...`);

    if (resourceType === "cobblestone") {
      // Ensure pickaxe
      const hasPickaxe = bot.inventory.items().some(it => it && typeof it.name === 'string' && it.name.endsWith('_pickaxe'));
      if (!hasPickaxe) {
        bot.chat && bot.chat("No pickaxe found. Crafting a wooden pickaxe...");
        try {
          // expects craftWoodenTool to exist in the environment
          await craftWoodenTool(bot, "pickaxe", "birch_planks", 6);
          await bot.waitForTicks(2);
        } catch (err) {
          bot.chat && bot.chat(`Failed to craft a pickaxe: ${err.message}`);
          // Continue; mining will likely fail if no tool, but let mineBlock handle that
        }
      }

      // Mine stone to get cobblestone
      try {
        const gained = await mineBlock(bot, "stone", need);
        if (typeof gained === "number") {
          current = getCurrentCount();
          bot.chat && bot.chat(`Mining attempt gained ${gained} cobblestone. Now have ${current}/${targetTotal}.`);
        } else {
          current = getCurrentCount();
          bot.chat && bot.chat(`Mining attempt finished. Now have ${current}/${targetTotal}.`);
        }
      } catch (err) {
        bot.chat && bot.chat(`Mining failed: ${err.message}`);
      }

    } else if (resourceType === "logs" || resourceType === "wood_logs") {
      // First try nearby
      const nearby = findNearbyLogBlock(32);
      if (nearby) {
        bot.chat && bot.chat(`Found nearby ${nearby.name} at ${nearby.position}. Mining up to ${need}...`);
        try {
          await mineBlock(bot, nearby.name, need);
          await bot.waitForTicks(2);
          current = getCurrentCount();
          bot.chat && bot.chat(`After mining: have ${current}/${targetTotal} logs.`);
          if (current >= targetTotal) return current;
          // continue to next attempt if not enough
          continue;
        } catch (err) {
          bot.chat && bot.chat(`Error mining ${nearby.name}: ${err.message}`);
          // fall through to exploration
        }
      }

      // Explore for logs
      const dir = randomHorizontalDirection();
      bot.chat && bot.chat(`No logs within 32 blocks. Exploring in direction (${dir.x},${dir.y},${dir.z}) for up to ${exploreTime}s...`);
      try {
        const found = await exploreUntil(bot, dir, exploreTime, () => {
          return findNearbyLogBlock() || null;
        });
        if (found) {
          bot.chat && bot.chat(`Exploration found ${found.name} at ${found.position}. Mining up to ${targetTotal - current}...`);
          try {
            await mineBlock(bot, found.name, targetTotal - current);
            await bot.waitForTicks(2);
            current = getCurrentCount();
            bot.chat && bot.chat(`After mining: have ${current}/${targetTotal} logs.`);
            if (current >= targetTotal) return current;
          } catch (err) {
            bot.chat && bot.chat(`Failed to mine found log: ${err.message}`);
          }
        } else {
          bot.chat && bot.chat(`Exploration did not find any logs within ${exploreTime}s.`);
        }
      } catch (err) {
        bot.chat && bot.chat(`Exploration error: ${err.message}`);
      }

    } else {
      // Generic fallback: try to mine a block with the same name as resourceType
      try {
        const gained = await mineBlock(bot, String(resourceType), need);
        await bot.waitForTicks(2);
        current = getCurrentCount();
        bot.chat && bot.chat(`After mining ${resourceType}: have ${current}/${targetTotal}.`);
      } catch (err) {
        bot.chat && bot.chat(`Failed to obtain ${resourceType}: ${err.message}`);
      }
    }

    // small delay to avoid tight loop
    await new Promise(r => setTimeout(r, 500));
    current = getCurrentCount();
  }

  // Final check
  current = getCurrentCount();
  if (current >= targetTotal) {
    bot.chat && bot.chat(`Success: have ${current}/${targetTotal} ${resourceType}.`);
    return current;
  } else {
    const msg = `Failed to obtain ${targetTotal} ${resourceType} after ${attempts} attempts. I have ${current}.`;
    bot.chat && bot.chat(msg);
    throw new Error(msg);
  }
}

nodes.description:
async function craftSticks(bot, targetTotal = 2) {
    // Validates inputs and ensures a bot instance and a positive numeric target, then checks current stick count and returns immediately if the target is already met. If more sticks are needed it computes how many crafting executions are required (sticks yield 4 per craft) and how many planks are required. If there are not enough planks it attempts to obtain missing planks, preferring an existing plank variant or converting logs to planks as available, then re-checks inventory. Once sufficient planks are available it performs the required stick crafting, waits for inventory synchronization, and returns the updated stick count. Errors are thrown for invalid input or if it cannot obtain enough planks.
}

nodes.code:
async function craftSticks(bot, targetTotal = 2) {
  // Use the shared init helper to get mcData and inventory helpers
  const {
    mcData,
    getItemCountByName,
    findPlankVariantInInventory,
    findLogVariantInInventory
  } = await getMcDataAndHelpers(bot);

  // Basic validation
  if (!bot) throw new Error("Bot instance is required");
  if (typeof targetTotal !== "number" || targetTotal <= 0) {
    throw new Error("targetTotal must be a positive number");
  }

  try {
    bot.chat(`I will ensure I have ${targetTotal} stick(s).`);

    // 1) Check current sticks
    let currentSticks = getItemCountByName("stick");
    if (currentSticks >= targetTotal) {
      bot.chat(`I already have ${currentSticks} stick(s). Nothing to do.`);
      return currentSticks;
    }

    // 2) Determine how many craft executions are needed
    const sticksPerExecution = 4; // standard Minecraft stick recipe yields 4
    const needed = targetTotal - currentSticks;
    const executions = Math.ceil(needed / sticksPerExecution);

    bot.chat(`Need ${needed} more stick(s) -> will run stick recipe ${executions} time(s).`);

    // 3) Ensure enough planks for stick recipe
    // Each stick recipe execution consumes 2 planks
    const planksNeeded = executions * 2;
    const plankVariantInventory = findPlankVariantInInventory(); // e.g., 'birch_planks'
    let plankCount = 0;
    if (plankVariantInventory) {
      plankCount = getItemCountByName(plankVariantInventory);
    } else {
      // No planks in inventory; check if we have any planks by any name (defensive)
      plankCount = bot.inventory.items()
        .filter(it => it && it.name && it.name.endsWith("_planks"))
        .reduce((s, it) => s + it.count, 0);
    }

    // If not enough planks, delegate to the specialized plank-crafting skill.
    // Compute missing planks and pick preferred variants if available.
    if (plankCount < planksNeeded) {
      bot.chat(`Only have ${plankCount} planks; need ${planksNeeded}. Attempting to craft missing planks.`);

      const missingPlanks = Math.max(0, planksNeeded - plankCount);
      let chosenPlankVariant = plankVariantInventory;
      let chosenLogVariant = null;
      if (!chosenPlankVariant) {
        const logVariant = findLogVariantInInventory();
        if (logVariant) {
          chosenPlankVariant = logVariant.replace(/_log$/, "_planks");
          chosenLogVariant = logVariant;
        }
      }

      try {
        if (missingPlanks > 0) {
          if (chosenPlankVariant) {
            await craftBirchPlanks(bot, missingPlanks, { plankVariant: chosenPlankVariant, logVariant: chosenLogVariant, interpretAsDelta: true });
          } else {
            // Let craftBirchPlanks default to birch_planks/birch_log
            await craftBirchPlanks(bot, missingPlanks, { interpretAsDelta: true });
          }
        }
      } catch (err) {
        try { bot.chat(`Failed to craft planks: ${err.message}`); } catch (_) {}
        throw err;
      }

      // craftBirchPlanks performs verification; re-sync and re-evaluate locally.
      await waitForInventorySync(bot);
      const plankNameToCheck = chosenPlankVariant || 'birch_planks';
      plankCount = getItemCountByName(plankNameToCheck);
      bot.chat(`Now have ${plankCount} ${plankNameToCheck}.`);
      if (plankCount < planksNeeded) {
        bot.chat(`Still do not have enough planks (${plankCount} < ${planksNeeded}). Aborting.`);
        throw new Error("Failed to obtain enough planks for sticks");
      }
    } else {
      bot.chat(`Have sufficient planks (${plankCount}) to craft sticks.`);
    }

    // 4) Craft sticks
    bot.chat(`Crafting sticks: running craftItem(bot, "stick", ${executions})...`);
    await craftItem(bot, "stick", executions);
    await waitForInventorySync(bot); // allow inventory to sync

    // 5) Report final count
    currentSticks = getItemCountByName("stick");
    bot.chat(`Done. I now have ${currentSticks} stick(s).`);
    return currentSticks;
  } catch (err) {
    try { bot.chat(`Failed to craft sticks: ${err.message}`); } catch (_) {}
    throw err;
  }
}

async function getMcDataAndHelpers(bot) {
  // CRITICAL: declare mcData at the very beginning
  if (!bot) throw new Error("Bot instance is required");
  const mcData = require("minecraft-data")(bot.version);

  // Helper: get total count of an item name in inventory
  function getItemCount(itemName) {
    if (!itemName) return 0;
    return bot.inventory.items()
      .filter(it => it && it.name === itemName)
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Alias kept for callers that used a slightly different name
  function getItemCountByName(name) {
    return getItemCount(name);
  }

  // Helper: find any plank variant in inventory (returns item name or null)
  function findPlankVariantInInventory() {
    const items = bot.inventory.items();
    for (const it of items) {
      if (!it || !it.name) continue;
      if (it.name.endsWith("_planks")) return it.name;
    }
    return null;
  }

  // Helper: find any log variant in inventory (returns item name or null)
  function findLogVariantInInventory() {
    const items = bot.inventory.items();
    for (const it of items) {
      if (!it || !it.name) continue;
      if (it.name.endsWith("_log")) return it.name;
    }
    return null;
  }

  return {
    mcData,
    getItemCount,
    getItemCountByName,
    findPlankVariantInInventory,
    findLogVariantInInventory
  };
}

