async function waitForInventorySync(bot, ticks = 2) {
  // Self-contained helper to wait a small number of ticks for inventory / server sync.
  // Validates arguments and uses bot.waitForTicks if available; otherwise falls back to a timeout.

  if (!bot) throw new Error("Bot instance is required");
  if (typeof ticks !== "number" || ticks < 0) {
    throw new Error("ticks must be a non-negative number");
  }

  // Prefer bot.waitForTicks when available (common in mineflayer environments).
  if (typeof bot.waitForTicks === "function") {
    return await bot.waitForTicks(ticks);
  }

  // Fallback: approximate a tick as 50ms (Minecraft tick).
  const ms = Math.round(Math.max(0, ticks) * 50);
  await new Promise((resolve) => setTimeout(resolve, ms));
}

