nodes.description:
async function craftFurnace(bot, count = 1, maxTableDistance = 6) {
    // Validates inputs and server item data, then computes how much cobblestone is required (8 per furnace) and checks the bot's inventory for that amount. If cobblestone is lacking it attempts to obtain the remainder by mining and errors out if it cannot get enough. Next it ensures a crafting table is placed nearby within the given max distance, crafts the requested number of furnaces, waits briefly for inventory synchronization, and finally verifies and returns how many furnaces are now in inventory, throwing descriptive errors on failures.
}

nodes.code:
async function craftFurnace(bot, count = 1, maxTableDistance = 6) {
  // MUST declare mcData at the very beginning per environment rules
  const mcData = require("minecraft-data")(bot.version);

  // Helper: total count of an item name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter((it) => it && it.name === name)
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Validation (delegated to shared validator)
  await ensureBotAndPositiveCount(bot, count);
  if (typeof maxTableDistance !== "number" || maxTableDistance <= 0) {
    throw new Error("maxTableDistance must be a positive number");
  }

  // Verify that mcData knows required items
  const furnaceItem = mcData.itemsByName["furnace"];
  const cobbleBlock = mcData.blocksByName["cobblestone"];
  if (!furnaceItem) {
    throw new Error("This server version does not recognize 'furnace' in mcData");
  }
  if (!cobbleBlock) {
    throw new Error("This server version does not recognize 'cobblestone' in mcData");
  }

  const requiredCobble = 8 * count;
  let haveCobble = getItemCount("cobblestone");
  bot.chat(`Preparing to craft ${count} furnace(s). Need ${requiredCobble} cobblestone, have ${haveCobble}.`);

  // If missing cobblestone, attempt to mine more (uses provided skill mineBlock)
  if (haveCobble < requiredCobble) {
    const missing = requiredCobble - haveCobble;
    bot.chat(`I need ${missing} more cobblestone. Mining...`);
    try {
      const gained = await mineBlock(bot, "cobblestone", missing);
      // mineBlock returns number gained; update haveCobble
      haveCobble = getItemCount("cobblestone");
      bot.chat(`Finished mining. Now have ${haveCobble} cobblestone.`);
      if (haveCobble < requiredCobble) {
        throw new Error(`Failed to obtain enough cobblestone (${haveCobble}/${requiredCobble}).`);
      }
    } catch (err) {
      throw new Error(`Failed to mine cobblestone: ${err.message}`);
    }
  }

  // Ensure a placed crafting table exists (setupCraftingTable will craft/place if needed)
  bot.chat("Ensuring a crafting table is placed nearby...");
  try {
    await setupCraftingTable(bot, maxTableDistance);
    // give some ticks to ensure inventory / world state sync
    await bot.waitForTicks(2);
  } catch (err) {
    throw new Error(`Failed to ensure a placed crafting table: ${err.message}`);
  }

  // Now craft the furnace(s) using existing craftItem primitive
  bot.chat(`Crafting ${count} furnace(s) now...`);
  try {
    await craftItem(bot, "furnace", count);
    // wait briefly for inventory to update
    await bot.waitForTicks(2);
  } catch (err) {
    throw new Error(`Crafting furnace failed: ${err.message}`);
  }

  // Verify result
  const finalFurnaces = getItemCount("furnace");
  if (finalFurnaces >= count) {
    bot.chat(`Success: I have ${finalFurnaces} furnace(s) in inventory.`);
    return finalFurnaces;
  } else {
    bot.chat(`Craft reported success but only found ${finalFurnaces} furnace(s).`);
    return finalFurnaces;
  }
}

async function ensureBotAndPositiveCount(bot, count, paramName = 'count') {
  // Self-contained validator: ensures bot exists and that count is a positive number.
  // paramName is only used to customize the thrown error message for count-like params.

  // Validation
  if (!bot) throw new Error('Bot instance is required');
  if (typeof count !== 'number' || count <= 0) {
    // Preserve the original default error text when paramName is the default 'count'
    if (paramName === 'count') {
      throw new Error('count must be a positive number');
    }
    throw new Error(`${paramName} must be a positive number`);
  }

  // Return true for convenience (caller can await but doesn't need the return)
  return true;
}

