async function craftIronPickaxe(bot, count = 1, maxTableDistance = 6) {
  // Wrapper for iron pickaxe
  return await generalCraftTool(bot, 'iron', 'pickaxe', count, { maxTableDistance });
}

async function generalCraftTool(bot, material, toolType = 'pickaxe', count = 1, options = {}) {
  // MUST declare mcData and Vec3 first
  const mcData = require('minecraft-data')(bot.version);
  const { Vec3 } = require('vec3');

  // Merge options with defaults
  const {
    plankVariant = 'birch_planks',
    maxTableDistance = 6,
    maxMineAttempts = 3,
    smeltTimeout = 60,
    ensureIronAttempts = 5,
    exploreTime = 60
  } = options || {};

  // Helper: total item count by name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter((it) => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Small helper to wait for inventory sync (graceful fallback)
  async function waitForInventorySyncOrTick() {
    try {
      if (typeof waitForInventorySync === 'function') {
        await waitForInventorySync(bot);
        return;
      }
    } catch (e) {
      // ignore and fallback
    }
    // fallback minimal wait
    try { await bot.waitForTicks(2); } catch (_) {}
  }

  // Validation
  if (!bot) throw new Error('Bot instance required');
  if (typeof count !== 'number' || count <= 0) throw new Error('count must be a positive number');
  if (!material) throw new Error('material parameter is required');

  // Standard requirements per toolType (can be extended)
  const requirementsPerTool = {
    pickaxe: { materialPer: 3, sticks: 2, needsTable: true },
    axe: { materialPer: 3, sticks: 2, needsTable: true },
    shovel: { materialPer: 1, sticks: 2, needsTable: true },
    sword: { materialPer: 2, sticks: 1, needsTable: true },
    // add more if needed
  };

  const req = requirementsPerTool[toolType];
  if (!req) throw new Error(`Unsupported toolType: ${toolType}`);

  // Determine crafted item name
  let craftedName;
  if (material === 'wood') {
    // Older/common name: wooden_<toolType>
    craftedName = `wooden_${toolType}`;
  } else {
    craftedName = `${material}_${toolType}`;
  }

  // Validate mcData knows the crafted item
  if (!mcData.itemsByName[craftedName]) {
    throw new Error(`${craftedName} is not recognized by mcData for this server version`);
  }

  bot.chat && bot.chat(`Attempting to craft ${count} ${craftedName}(s)...`);

  // 0) Early return if already have enough
  const haveAlready = getItemCount(craftedName);
  if (haveAlready >= count) {
    bot.chat && bot.chat(`I already have ${haveAlready} ${craftedName}(s). Nothing to do.`);
    return haveAlready;
  }

  // 1) Ensure material-specific primary ingredient(s)
  const materialNeededTotal = req.materialPer * count;

  if (material === 'iron') {
    const ingotName = 'iron_ingot';
    let haveIngots = getItemCount(ingotName);

    if (haveIngots < materialNeededTotal) {
      const missing = materialNeededTotal - haveIngots;
      bot.chat && bot.chat(`Need ${missing} more ${ingotName}(s). Trying to smelt or obtain ore.`);

      try {
        // smeltIronIngots(bot, count, exploreTime)
        if (typeof smeltIronIngots === 'function') {
          await smeltIronIngots(bot, missing, smeltTimeout);
        }
      } catch (err) {
        bot.chat && bot.chat(`smeltIronIngots attempt failed: ${err.message}`);
      }

      haveIngots = getItemCount(ingotName);
      if (haveIngots < materialNeededTotal) {
        // Try to ensure iron ore/raw and smelt again
        const targetTotalRaw = Math.max(materialNeededTotal, haveIngots + 1);
        try {
          if (typeof ensureIronOre === 'function') {
            await ensureIronOre(bot, targetTotalRaw, ensureIronAttempts, exploreTime);
          }
          const stillMissing = materialNeededTotal - getItemCount(ingotName);
          if (stillMissing > 0 && typeof smeltIronIngots === 'function') {
            await smeltIronIngots(bot, stillMissing, smeltTimeout);
          }
        } catch (err) {
          bot.chat && bot.chat(`ensureIronOre/smelt retry failed: ${err.message}`);
          throw new Error(`Cannot obtain required ${ingotName}(s): ${err.message}`);
        }
        haveIngots = getItemCount(ingotName);
      }

      bot.chat && bot.chat(`Have ${haveIngots}/${materialNeededTotal} ${ingotName}(s).`);
      if (haveIngots < materialNeededTotal) {
        throw new Error(`Insufficient ${ingotName}s after attempts (${haveIngots}/${materialNeededTotal}).`);
      }
    }
  } else if (material === 'stone') {
    const cobbleName = 'cobblestone';
    let haveCobble = getItemCount(cobbleName);
    let attempts = 0;
    while (haveCobble < materialNeededTotal && attempts < maxMineAttempts) {
      const missing = materialNeededTotal - haveCobble;
      bot.chat && bot.chat(`Need ${missing} more ${cobbleName}. Attempting to mine (attempt ${attempts + 1}/${maxMineAttempts})...`);
      try {
        if (typeof mineBlock === 'function') {
          await mineBlock(bot, cobbleName, missing);
          await waitForInventorySyncOrTick();
          haveCobble = getItemCount(cobbleName);
          bot.chat && bot.chat(`Now have ${haveCobble}/${materialNeededTotal} ${cobbleName}.`);
        } else {
          throw new Error('mineBlock skill is not available');
        }
      } catch (err) {
        bot.chat && bot.chat(`Mining attempt failed: ${err.message}`);
      }
      attempts++;
    }
    if (haveCobble < materialNeededTotal) {
      throw new Error(`Unable to obtain required ${cobbleName} (${haveCobble}/${materialNeededTotal}) after ${maxMineAttempts} attempts`);
    }
  } else if (material === 'wood') {
    // wood uses a plank variant (plankVariant), need req.materialPer * count planks
    const plankName = plankVariant;
    if (!mcData.itemsByName[plankName]) {
      throw new Error(`Unknown plank variant: ${plankName}`);
    }
    let havePlanks = getItemCount(plankName);
    if (havePlanks < materialNeededTotal) {
      const missing = materialNeededTotal - havePlanks;
      const executions = Math.max(1, Math.ceil(missing / 4)); // 1 log -> 4 planks per craft execution often
      bot.chat && bot.chat(`Need ${missing} more ${plankName}. Attempting to craft ${executions} time(s).`);
      try {
        await craftItem(bot, plankName, executions);
        await waitForInventorySyncOrTick();
        havePlanks = getItemCount(plankName);
      } catch (err) {
        bot.chat && bot.chat(`Plank crafting failed: ${err.message}. Trying to obtain logs and retry.`);
        try {
          if (typeof ensureLogs === 'function') {
            await ensureLogs(bot, 1);
          }
          await craftItem(bot, plankName, executions);
          await waitForInventorySyncOrTick();
          havePlanks = getItemCount(plankName);
        } catch (err2) {
          throw new Error(`Failed to obtain or craft ${plankName}: ${err2.message}`);
        }
      }
      if (havePlanks < materialNeededTotal) {
        throw new Error(`Unable to obtain required ${plankName}. Have ${havePlanks}, need ${materialNeededTotal}.`);
      }
      bot.chat && bot.chat(`Now have ${havePlanks} ${plankName}.`);
    }
  } else {
    // Unknown material type - assume the recipe consumes an item named <material> (best-effort)
    const itemName = `${material}`; // e.g. 'diamond' if passed
    let have = getItemCount(itemName);
    if (have < materialNeededTotal) {
      throw new Error(`Unsupported material provisioning for '${material}'. Have ${have}, need ${materialNeededTotal}.`);
    }
  }

  // 2) Ensure sticks
  const neededSticksTotal = (req.sticks || 0) * count;
  if (neededSticksTotal > 0) {
    let haveSticks = getItemCount('stick');
    if (haveSticks < neededSticksTotal) {
      bot.chat && bot.chat(`Need ${neededSticksTotal} sticks but have ${haveSticks}. Crafting sticks...`);
      // craftSticks(bot, targetTotal) may be available; otherwise craftItem('stick') recipe
      try {
        if (typeof craftSticks === 'function') {
          await craftSticks(bot, neededSticksTotal);
        } else {
          const missing = neededSticksTotal - haveSticks;
          const execs = Math.max(1, Math.ceil(missing / 4));
          await craftItem(bot, 'stick', execs);
        }
        await waitForInventorySyncOrTick();
        haveSticks = getItemCount('stick');
        bot.chat && bot.chat(`Now have ${haveSticks} sticks.`);
      } catch (err) {
        throw new Error(`Failed to ensure sticks: ${err.message}`);
      }
      if (haveSticks < neededSticksTotal) {
        throw new Error(`Insufficient sticks after attempts (${haveSticks}/${neededSticksTotal}).`);
      }
    } else {
      bot.chat && bot.chat(`Have sufficient sticks: ${haveSticks}/${neededSticksTotal}`);
    }
  }

  // 3) Ensure a crafting table is placed/nearby if required
  if (req.needsTable) {
    bot.chat && bot.chat('Ensuring a placed crafting table is available...');
    try {
      if (typeof setupCraftingTable === 'function') {
        await setupCraftingTable(bot, maxTableDistance);
      } else {
        // fallback: try to find a placed crafting table within distance
        const craftingTableBlock = mcData.blocksByName['crafting_table'];
        if (!craftingTableBlock) throw new Error("This server version does not recognize 'crafting_table' in mcData.");
        const placed = bot.findBlock({ matching: craftingTableBlock.id, maxDistance: maxTableDistance });
        if (!placed) {
          // try to craft a table and place it if helper exists
          if (mcData.itemsByName['crafting_table'] && getItemCount('crafting_table') === 0) {
            await craftItem(bot, 'crafting_table', 1);
            await waitForInventorySyncOrTick();
          }
          if (getItemCount('crafting_table') > 0) {
            // find a place position
            let placePos = null;
            try {
              if (typeof findNearbyOpenArea === 'function') {
                placePos = await findNearbyOpenArea(bot, bot.entity ? bot.entity.position.floored() : null, Math.max(4, maxTableDistance));
              }
            } catch (_) {
              placePos = null;
            }
            if (!placePos) {
              if (!bot.entity) throw new Error('Bot entity undefined; cannot place crafting_table.');
              placePos = bot.entity.position.floored().offset(1, 0, 0);
            }
            if (typeof placeItem === 'function') {
              await placeItem(bot, 'crafting_table', placePos);
              await waitForInventorySyncOrTick();
            } else {
              throw new Error('No placeItem helper available to place the crafting table');
            }
          } else {
            throw new Error('No crafting_table item available and cannot craft one');
          }
        }
      }
      await waitForInventorySyncOrTick();
    } catch (err) {
      bot.chat && bot.chat(`Failed to ensure crafting table: ${err.message}`);
      throw err;
    }
  }

  // 4) Craft the tool(s)
  bot.chat && bot.chat(`Crafting ${count} ${craftedName}(s) now...`);
  try {
    await craftItem(bot, craftedName, count);
    await waitForInventorySyncOrTick();
  } catch (err) {
    bot.chat && bot.chat(`Crafting ${craftedName} failed: ${err.message}`);
    throw err;
  }

  const finalCount = getItemCount(craftedName);
  if (finalCount >= 1) {
    bot.chat && bot.chat(`Success: I now have ${finalCount} ${craftedName}(s).`);
    return finalCount;
  } else {
    bot.chat && bot.chat(`Craft reported success but ${craftedName} not found in inventory.`);
    return finalCount;
  }
}

