nodes.description:
async function craftDiamondPickaxe(bot, count = 1, options = {}) {
    // Validates that the server's mcData recognizes diamond_pickaxe and that count is a positive number, then computes required diamonds and sticks and throws an error if there are not enough diamonds in inventory; it ensures enough sticks are present (crafting more if needed) and that a crafting table exists nearby (placing one if necessary). It then crafts the requested number of diamond pickaxes and waits for inventory synchronization. Finally it counts how many diamond pickaxes are now in the inventory and returns that final count, while propagating any errors to the caller.
}

nodes.code:
async function craftDiamondPickaxe(bot, count = 1, options = {}) {
  // REQUIRED: declare mcData and Vec3 first to avoid TDZ errors
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Options with defaults
  const {
    tableMaxDistance = 32,
    placeTableRadius = 8
  } = options || {};

  // Helper: total item count of a given item name in inventory
  function getItemCount(name) {
    return bot.inventory
      .items()
      .filter(it => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Helper: ensure we have enough sticks total (craftSticks expects a target total)
  async function ensureSticksTotal(targetTotal) {
    const have = getItemCount("stick");
    if (have >= targetTotal) {
      bot.chat(`Have ${have} sticks (need ${targetTotal}).`);
      return have;
    }
    bot.chat(`Need ${targetTotal} sticks, currently have ${have}. Crafting sticks...`);
    await craftSticks(bot, targetTotal);
    // allow inventory sync
    await bot.waitForTicks(2);
    const now = getItemCount("stick");
    bot.chat(`Now have ${now} sticks.`);
    return now;
  }

  // Helper: ensure there is a placed crafting table nearby (within tableMaxDistance).
  // If none exists, delegate placement & crafting to setupCraftingTable(bot, placeTableRadius).
  async function ensurePlacedCraftingTable() {
    // Defensive mcData checks similar to original behavior
    const craftingTableBlockDef = mcData.blocksByName["crafting_table"];
    const craftingTableItemDef = mcData.itemsByName["crafting_table"];
    if (!craftingTableBlockDef || !craftingTableItemDef) {
      throw new Error("This server version does not recognize 'crafting_table' in mcData.");
    }

    // Fast-path: if a crafting table is already placed nearby, return it
    const placed = bot.findBlock({
      matching: craftingTableBlockDef.id,
      maxDistance: tableMaxDistance
    });
    if (placed) {
      bot.chat(`Found placed crafting_table at ${placed.position}.`);
      return placed;
    }

    // Otherwise delegate the heavy lifting to setupCraftingTable
    // setupCraftingTable returns an object with position
    const setupResult = await setupCraftingTable(bot, placeTableRadius);
    await bot.waitForTicks(8);
    let placePos = null;
    if (setupResult) {
      if (setupResult.position) placePos = setupResult.position;
      else placePos = setupResult;
    }
    const placedBlock = bot.blockAt(placePos);
    if (!placedBlock || placedBlock.name !== "crafting_table") {
      throw new Error("Failed to place crafting_table at target position.");
    }
    bot.chat("Placed crafting_table.");
    return placedBlock;
  }

  // Begin main logic
  try {
    // Validate mcData entries
    const pickaxeName = "diamond_pickaxe";
    if (!mcData.itemsByName[pickaxeName]) {
      throw new Error(`${pickaxeName} is not recognized by mcData for this server version.`);
    }

    if (typeof count !== "number" || count <= 0) {
      throw new Error("count must be a positive number.");
    }

    const diamondsNeeded = 3 * count;
    const sticksNeeded = 2 * count;

    const haveDiamonds = getItemCount("diamond");
    if (haveDiamonds < diamondsNeeded) {
      throw new Error(`Insufficient diamonds: have ${haveDiamonds}, need ${diamondsNeeded}. You must mine or obtain more diamonds first.`);
    }
    bot.chat(`Have ${haveDiamonds} diamonds; need ${diamondsNeeded}.`);

    // Ensure sticks total
    await ensureSticksTotal(sticksNeeded);

    // Ensure placed crafting table
    await ensurePlacedCraftingTable();

    // Craft the diamond pickaxe(s)
    bot.chat(`Crafting ${count} ${pickaxeName}(s)...`);
    await craftItem(bot, pickaxeName, count);
    // wait for inventory sync
    await bot.waitForTicks(4);

    const finalCount = getItemCount(pickaxeName);
    if (finalCount >= 1) {
      bot.chat(`Finished: now have ${finalCount} ${pickaxeName}(s).`);
    } else {
      bot.chat(`Craft reported but ${pickaxeName} not found in inventory.`);
    }

    return finalCount;
  } catch (err) {
    // Provide a chat message and rethrow for caller handling
    try { bot.chat(`Error in craftDiamondPickaxe: ${err.message}`); } catch (_) {}
    throw err;
  }
}

nodes.description:
async function findOre(bot, mine = false, count = 1, exploreTime = 60, maxAttempts = 3) {
    // Validates the bot and parameters, searches for nearby redstone or deepslate redstone within ~32 blocks and, if not found, repeatedly explores downward for up to exploreTime seconds across up to maxAttempts attempts; once an ore block is located it moves near the block and, if mine is false, returns the block name and position without mining, otherwise it attempts to mine up to count of that block, waits briefly for inventory sync, and returns the number of items gained; it throws errors if the bot/entity is missing, the ore cannot be found within the search/explore budget, or movement/mining fails.
}

nodes.code:
async function findOre(bot, mine = false, count = 1, exploreTime = 60, maxAttempts = 3) {
  // Initialize mcData and Vec3 at the very beginning
  const { mcData, Vec3 } = await initMcDataVec3(bot);

  // Helper: search for either redstone ore variant within 32 blocks
  function locateRedstoneBlock() {
    // Defensive checks for mcData entries
    const r1 = mcData.blocksByName['redstone_ore'];
    const r2 = mcData.blocksByName['deepslate_redstone_ore'];
    // If neither type exists in this version, return null
    if (!r1 && !r2) return null;
    const block = bot.findBlock({
      matching: b => {
        if (!b) return false;
        const name = b.name;
        if (r1 && name === 'redstone_ore') return true;
        if (r2 && name === 'deepslate_redstone_ore') return true;
        return false;
      },
      maxDistance: 32
    });
    return block || null;
  }

  // Helper: move near a block (uses global gotoWithTimeout)
  async function moveNearBlock(block) {
    if (!block || !block.position) throw new Error("Invalid block for movement");
    const pos = block.position;
    const goal = new GoalNear(pos.x, pos.y, pos.z, 2);
    await gotoWithTimeout(bot, goal, 30000, `redstone ore at ${pos.x},${pos.y},${pos.z}`);
  }

  // Start of main logic
  if (!bot) throw new Error("Bot instance required");
  if (!bot.entity) throw new Error("Bot entity undefined; cannot operate");

  // Validate parameters
  if (typeof mine !== 'boolean') mine = Boolean(mine);
  if (typeof count !== 'number' || count < 1) count = 1;
  if (typeof exploreTime !== 'number' || exploreTime < 1) exploreTime = 60;
  if (typeof maxAttempts !== 'number' || maxAttempts < 1) maxAttempts = 3;
  bot.chat(`Searching for redstone ore (mine=${mine}, count=${count})...`);
  let attempt = 0;
  let foundBlock = null;
  while (attempt < maxAttempts && !foundBlock) {
    attempt++;
    foundBlock = locateRedstoneBlock();
    if (foundBlock) break;
    bot.chat(`No redstone ore within 32 blocks (attempt ${attempt}/${maxAttempts}). Exploring for up to ${exploreTime}s...`);

    // Explore downward because redstone tends to be deep underground
    try {
      const found = await exploreUntil(bot, new Vec3(0, -1, 0), exploreTime, () => {
        return locateRedstoneBlock() || null;
      });
      if (found) {
        // exploreUntil returns a Block (from our callback) or null
        // But our callback returns a block from locateRedstoneBlock(); re-run locate to get actual block object
        foundBlock = locateRedstoneBlock();
        if (foundBlock) break;
      } else {
        bot.chat("Exploration did not find redstone ore.");
      }
    } catch (err) {
      bot.chat(`Exploration error: ${err.message}`);
    }
  }
  if (!foundBlock) {
    bot.chat("Failed to find redstone ore after attempts.");
    throw new Error("No redstone ore found within search/explore budget.");
  }
  bot.chat(`Found ${foundBlock.name} at ${foundBlock.position}. Moving there...`);
  try {
    await moveNearBlock(foundBlock);
  } catch (err) {
    bot.chat(`Failed to move near redstone ore: ${err.message}`);
    throw err;
  }
  if (!mine) {
    bot.chat(`Located redstone ore at ${foundBlock.position}. Not mining (mine=false).`);
    return {
      found: true,
      blockName: foundBlock.name,
      position: foundBlock.position.clone(),
      mined: 0
    };
  }

  // Mining branch: use mineBlock skill (expects block name string)
  const blockName = foundBlock.name;
  bot.chat(`Mining up to ${count} ${blockName}(s)...`);

  // mineBlock expects a BLOCK NAME string (not Block object). Use blockName directly.
  try {
    const gained = await mineBlock(bot, blockName, count);
    await bot.waitForTicks(2); // allow inventory to sync
    bot.chat(`Mining finished. Gained ${gained} item(s) (likely redstone dust).`);
    return {
      found: true,
      blockName,
      position: foundBlock.position.clone(),
      mined: gained
    };
  } catch (err) {
    bot.chat(`Mining failed: ${err.message}`);
    throw err;
  }
}

