async function ensureRedstone(bot, targetTotal = 16, exploreTime = 60, maxAttempts = 5) {
    // Validates the bot and server item definitions for redstone, then checks the current redstone count and returns immediately if the target (default 16) is already met; otherwise it repeatedly attempts to collect more redstone up to a maximum number of attempts by estimating how many ore blocks to mine per iteration and invoking an ore-finding/mining routine, waiting briefly for inventory sync after each try and updating the count; if the target is reached it returns the final count, and if not it throws an error after exhausting attempts.
}

nodes.code:
async function ensureRedstone(bot, targetTotal = 16, exploreTime = 60, maxAttempts = 5) {
  // Obtain shared helpers (mcData, Vec3, getItemCount)
  const { mcData, Vec3, getItemCount } = await provideInventoryHelpers(bot);

  // Defensive checks
  if (!bot) throw new Error("Bot instance required");
  if (!bot.entity) {
    bot.chat && bot.chat("I seem to be dead or disconnected; cannot ensure redstone right now.");
    throw new Error("bot.entity undefined");
  }

  // Verify mcData has redstone item name (common: 'redstone')
  const redstoneItemDef = mcData.itemsByName["redstone"];
  if (!redstoneItemDef) {
    throw new Error("mcData does not recognize item name 'redstone' for this server version.");
  }

  // Main loop: try up to maxAttempts to reach targetTotal redstone
  let current = getItemCount("redstone");
  bot.chat && bot.chat(`I have ${current}/${targetTotal} redstone. Beginning collection...`);
  if (current >= targetTotal) {
    bot.chat && bot.chat(`Already have ${current} redstone (target ${targetTotal}).`);
    return current;
  }

  let attempts = 0;
  // Conservative estimate: assume ~4 redstone dust per ore block (deepslate/normal average 4-5)
  const estimatedYieldPerBlock = 4;

  while (attempts < maxAttempts && current < targetTotal) {
    attempts++;
    const need = targetTotal - current;
    // Compute how many ore blocks to mine this iteration (mine a bit more to reduce iterations)
    const blocksToMine = Math.max(1, Math.ceil(need / estimatedYieldPerBlock));
    bot.chat && bot.chat(`Attempt ${attempts}/${maxAttempts}: trying to mine ~${blocksToMine} redstone ore block(s) (need ${need} dust).`);

    try {
      // Reuse the provided findOre skill to locate & mine redstone ore.
      // Signature: findOre(bot, mine = false, count = 1, exploreTime = 60, maxAttempts = 3)
      const result = await findOre(bot, true, blocksToMine, exploreTime, 3);
      // findOre returns an object with { found, blockName, position, mined } on success
      if (result && typeof result.mined === "number") {
        bot.chat && bot.chat(`findOre reported mined=${result.mined} items from ore.`);
      } else {
        bot.chat && bot.chat("findOre completed but reported no mined count.");
      }
    } catch (err) {
      // findOre may throw if it couldn't find or mine. Log and continue retrying up to maxAttempts.
      bot.chat && bot.chat(`findOre attempt failed: ${err.message}`);
    }

    // Allow inventory to sync
    await bot.waitForTicks(4);
    current = getItemCount("redstone");
    bot.chat && bot.chat(`After attempt ${attempts}, I have ${current}/${targetTotal} redstone.`);

    // If we made no progress this attempt, try again (loop continues). Conservative protection: increase attempts.
  }

  if (current >= targetTotal) {
    bot.chat && bot.chat(`Success: obtained ${current} redstone (target ${targetTotal}).`);
    return current;
  } else {
    const msg = `Failed to obtain ${targetTotal} redstone after ${attempts} attempts. Currently have ${current}.`;
    bot.chat && bot.chat(msg);
    throw new Error(msg);
  }
}

