nodes.description:
async function doSmeltIngots(bot, targetCount = 8, exploreTime = 60, placeRadius = 6) {
    // It ensures the bot reaches a target number of gold ingots by checking inventory and, if short, locating and mining nearby gold ore (including exploring if necessary) while equipping the best pickaxe available; it then crafts or places a furnace if none is found nearby, chooses an appropriate fuel source (coal/charcoal/logs/planks, with a best-effort attempt to obtain fuel if missing), smelts the required raw gold into ingots, and finally returns the resulting ingot count.
}

nodes.code:
async function doSmeltIngots(bot, targetCount = 8, exploreTime = 60, placeRadius = 6) {
  // Initialize mcData and Vec3 at the very beginning
  const { mcData, Vec3 } = await initMcDataVec3(bot);

  // Helper: total count of items by name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory.items().filter(it => it && it.name === name).reduce((s, it) => s + it.count, 0);
  }

  // Helper: choose best fuel available
  function chooseFuel(preferred = ["coal", "charcoal", "birch_log", "oak_log", "birch_planks", "oak_planks"]) {
    for (const fname of preferred) {
      const item = mcData.itemsByName[fname];
      if (item && bot.inventory.findInventoryItem(item.id, null)) return fname;
    }
    return null;
  }

  // Helper: choose best pickaxe in inventory (returns item object or null)
  function chooseBestPickaxe() {
    const pref = ["diamond_pickaxe", "netherite_pickaxe", "iron_pickaxe", "stone_pickaxe", "wooden_pickaxe"];
    for (const name of pref) {
      const it = mcData.itemsByName[name];
      if (it) {
        const found = bot.inventory.findInventoryItem(it.id, null);
        if (found) return found;
      }
    }
    return null;
  }

  // Helper: find nearest gold ore block (prefer deepslate then regular), returns {name, block} or null
  function findNearestGoldOre() {
    const oreCandidates = ["deepslate_gold_ore", "gold_ore"];
    for (const oreName of oreCandidates) {
      const def = mcData.blocksByName[oreName];
      if (!def) continue;
      const blk = bot.findBlock({
        matching: def.id,
        maxDistance: 32
      });
      if (blk) return {
        name: oreName,
        block: blk
      };
    }
    return null;
  }

  // Helper: explore once to find gold ore (single exploreUntil call)
  async function exploreForGoldOre(timeoutSeconds = exploreTime) {
    const oreCandidates = ["deepslate_gold_ore", "gold_ore"];
    // choose a random horizontal direction for exploration
    const dirOptions = [new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1), new Vec3(1, 0, 1), new Vec3(-1, 0, 1), new Vec3(1, 0, -1), new Vec3(-1, 0, -1)];
    const dir = dirOptions[Math.floor(Math.random() * dirOptions.length)];
    const found = await exploreUntil(bot, dir, timeoutSeconds, () => {
      for (const oreName of oreCandidates) {
        const def = mcData.blocksByName[oreName];
        if (!def) continue;
        const b = bot.findBlock({
          matching: def.id,
          maxDistance: 32
        });
        if (b) return {
          name: oreName,
          block: b
        };
      }
      return null;
    });
    if (!found) return null;
    return {
      name: found.name || found.block && found.block.name,
      block: found.block || null
    };
  }

  // Helper: try to move near a block position with a few offsets (bounded retries)
  async function approachBlockWithRetries(block, maxAttempts = 3) {
    // Try to move near the block.position; if it times out, try neighbor offsets
    const offsets = [new Vec3(0, 0, 0), new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1), new Vec3(1, 0, 1), new Vec3(-1, 0, -1)];
    const targetPos = block.position;
    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      const ofs = offsets[attempt % offsets.length];
      const tryPos = targetPos.plus(ofs);
      try {
        // moveNear is available in global helpers; fallback to gotoWithTimeout if needed
        if (typeof moveNear === "function") {
          await moveNear(bot, tryPos, 2);
        } else {
          await gotoWithTimeout(bot, new GoalNear(tryPos.x, tryPos.y, tryPos.z, 2), 30000, `approach ore at ${tryPos}`);
        }
        return true;
      } catch (err) {
        bot.chat && bot.chat(`Approach attempt ${attempt + 1} failed: ${err.message}`);
        // continue to next offset
      }
    }
    return false;
  }

  // Start main logic
  if (!bot) throw new Error("Bot instance required");
  bot.chat && bot.chat(`Starting doSmeltGoldIngots: target ${targetCount}`);
  const goldIngotName = "gold_ingot";
  const rawGoldName = "raw_gold";

  // 1) Check current gold ingots
  const haveIngots = getItemCount(goldIngotName);
  if (haveIngots >= targetCount) {
    bot.chat && bot.chat(`Already have ${haveIngots} ${goldIngotName}(s).`);
    return haveIngots;
  }
  let need = targetCount - haveIngots;
  bot.chat && bot.chat(`Need ${need} more ${goldIngotName}(s). Checking raw_gold in inventory...`);

  // 2) Ensure raw_gold items
  let haveRaw = getItemCount(rawGoldName);
  if (haveRaw < need) {
    bot.chat && bot.chat(`Have ${haveRaw} raw_gold, need ${need}. Searching for ore...`);
    // Try to find ore nearby, then explore if necessary
    let oreInfo = findNearestGoldOre();
    if (!oreInfo) {
      bot.chat && bot.chat("No gold ore within 32 blocks. Exploring to find gold ore...");
      oreInfo = await exploreForGoldOre();
    }
    if (!oreInfo || !oreInfo.block) {
      throw new Error("No gold ore found nearby or during exploration. Cannot obtain raw gold.");
    }
    bot.chat && bot.chat(`Found ore: ${oreInfo.name} at ${oreInfo.block.position}. Preparing to mine ${Math.max(0, need - haveRaw)}.`);

    // Equip best pickaxe before attempting approach / mining
    const bestPick = chooseBestPickaxe();
    if (bestPick) {
      try {
        await bot.equip(bestPick, "hand");
        bot.chat && bot.chat(`Equipped ${mcData.items[bestPick.type].name} for mining.`);
      } catch (e) {
        bot.chat && bot.chat(`Failed to equip preferred pickaxe: ${e.message}`);
      }
    } else {
      bot.chat && bot.chat("No pickaxe in inventory. Mining likely to fail (requires at least iron pickaxe for gold)." );
    }

    // Retry loop for mine attempts (bounded)
    let remaining = need - haveRaw;
    const maxMineAttempts = 3;
    let minedTotal = 0;
    for (let attempt = 0; attempt < maxMineAttempts && remaining > 0; attempt++) {
      bot.chat && bot.chat(`Mining attempt ${attempt + 1}/${maxMineAttempts}, need ${remaining} more raw_gold...`);
      // Try to approach
      const approached = await approachBlockWithRetries(oreInfo.block, 3);
      if (!approached) {
        bot.chat && bot.chat("Failed to approach ore after multiple attempts. Trying a brief exploration to reposition...");
        // small reposition exploration try
        const alt = await exploreForGoldOre(Math.min(30, exploreTime));
        if (alt && alt.block) {
          oreInfo = alt;
          bot.chat && bot.chat(`Found alternative ore at ${oreInfo.block.position}.`);
          // try to equip again
          const bestPick2 = chooseBestPickaxe();
          if (bestPick2) {
            try {
              await bot.equip(bestPick2, "hand");
            } catch (_) {}
          }
        } else {
          bot.chat && bot.chat("Exploration did not find alternate ore.");
        }
      }

      // Attempt to mine the needed delta (but don't request more than remaining)
      const toMine = Math.max(1, remaining); // mine at least 1
      try {
        const gained = await mineBlock(bot, oreInfo.name, toMine);
        minedTotal += gained;
        await bot.waitForTicks(2);
        haveRaw = getItemCount(rawGoldName);
        remaining = need - haveRaw;
        bot.chat && bot.chat(`Mining attempt result: gained ${gained} raw_gold. Now have ${haveRaw} (need ${Math.max(0, remaining)}).`);
        if (remaining <= 0) break;
        // if still need more, either locate another ore block or continue with same target
        const nextOre = findNearestGoldOre();
        if (nextOre) oreInfo = nextOre;
      } catch (err) {
        bot.chat && bot.chat(`Mining attempt ${attempt + 1} failed: ${err.message}`);
        // small wait before next attempt
        await new Promise(r => setTimeout(r, 1000));
        // optionally try to find another ore block nearby
        const alt = findNearestGoldOre();
        if (alt && alt.block) oreInfo = alt;
      }
    } // end mine attempts

    haveRaw = getItemCount(rawGoldName);
    if (haveRaw < need) {
      throw new Error(`Unable to obtain required raw_gold. Have ${haveRaw}, need ${need}.`);
    }
    bot.chat && bot.chat(`Collected required raw_gold: ${haveRaw}.`);
  } else {
    bot.chat && bot.chat(`Already have ${haveRaw} raw_gold; enough to smelt ${need} gold_ingots.`);
  }

  // 3) Ensure a visible/placed furnace (craft/place if needed). Use existing craftFurnace and placeItem helpers.
  const furnaceBlockDef = mcData.blocksByName["furnace"];
  if (!furnaceBlockDef) throw new Error("This server version does not recognize 'furnace' in mcData.");
  let furnaceBlock = bot.findBlock({
    matching: furnaceBlockDef.id,
    maxDistance: 32
  });
  if (!furnaceBlock) {
    bot.chat && bot.chat("No placed furnace nearby. Will craft/place one.");
    // Ensure we have a furnace item or craft one
    const furnaceItemDef = mcData.itemsByName["furnace"];
    if (!furnaceItemDef) throw new Error("This server version does not recognize 'furnace' item in mcData.");
    let haveFurnaceItem = bot.inventory.findInventoryItem(furnaceItemDef.id, null);
    if (!haveFurnaceItem) {
      bot.chat && bot.chat("No furnace item in inventory. Crafting...");
      await craftFurnace(bot, 1);
      await bot.waitForTicks(2);
      haveFurnaceItem = bot.inventory.findInventoryItem(furnaceItemDef.id, null);
      if (!haveFurnaceItem) {
        throw new Error("Failed to craft furnace item.");
      }
    }
    // find placement position
    let placePos = null;
    try {
      if (typeof findNearbyOpenArea === "function") {
        placePos = await findNearbyOpenArea(bot, bot.entity ? bot.entity.position.floored() : null, placeRadius);
      }
    } catch (e) {
      placePos = null;
    }
    if (!placePos) {
      if (!bot.entity) throw new Error("Bot entity undefined; cannot compute placement position.");
      placePos = bot.entity.position.floored().offset(1, 0, 0);
    }
    await placeItem(bot, "furnace", placePos);
    await bot.waitForTicks(4);
    furnaceBlock = bot.findBlock({
      matching: furnaceBlockDef.id,
      maxDistance: 32
    });
    if (!furnaceBlock) throw new Error("Placed furnace but cannot find it in the world.");
    bot.chat && bot.chat(`Placed furnace at ${furnaceBlock.position}.`);
  } else {
    bot.chat && bot.chat(`Found existing furnace at ${furnaceBlock.position}.`);
  }

  // 4) Choose fuel
  let fuelName = chooseFuel(["coal", "charcoal", "birch_log", "oak_log", "birch_planks", "oak_planks"]);
  if (!fuelName) {
    // Try to get some logs via ensureResource if available (best-effort)
    if (typeof ensureResource === "function") {
      try {
        await ensureResource(bot, "logs", 1, 3, exploreTime);
        fuelName = chooseFuel(["coal", "charcoal", "birch_log", "oak_log", "birch_planks", "oak_planks"]);
      } catch (e) {/* ignore */}
    }
  }
  if (!fuelName) {
    throw new Error("No fuel available in inventory (coal/charcoal/logs/planks). Cannot smelt.");
  }
  bot.chat && bot.chat(`Using ${fuelName} as fuel.`);

  // 5) Perform smelting
  const haveRawFinal = getItemCount(rawGoldName);
  const toSmelt = Math.min(need, haveRawFinal);
  if (toSmelt <= 0) {
    throw new Error(`Nothing to smelt: toSmelt=${toSmelt}, haveRaw=${haveRawFinal}, need=${need}`);
  }
  bot.chat && bot.chat(`Smelting ${toSmelt} raw_gold into gold_ingots...`);
  try {
    await smeltItem(bot, rawGoldName, fuelName, toSmelt);
    await bot.waitForTicks(4);
  } catch (err) {
    throw new Error(`Smelting failed: ${err.message}`);
  }

  // 6) Final report
  const finalIngots = getItemCount(goldIngotName);
  bot.chat && bot.chat(`Smelting complete. I now have ${finalIngots} ${goldIngotName}(s).`);
  return finalIngots;
}

async function smeltIngots(bot, ingotType, targetCount = 1, exploreTime = 60, placeRadius = 6) {
  // Generic smelting helper that covers multiple ingot types (gold, iron, ...)
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // A small per-ingot-type configuration to handle subtle differences
  const TYPE_MAP = {
    "gold_ingot": {
      rawNames: ["raw_gold"],
      oreCandidates: ["deepslate_gold_ore", "gold_ore"],
      useEnsureResource: false,
      ensureResourceKey: null,
      placeRadiusDefault: 6
    },
    "iron_ingot": {
      rawNames: ["raw_iron", "iron_ore"],
      oreCandidates: ["iron_ore"],
      useEnsureResource: true,
      ensureResourceKey: "iron",
      placeRadiusDefault: 6
    }
  };

  // Helper: total count of an item name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory.items()
      .filter(it => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Helper: choose a fuel from a preference list
  function chooseFuel(preferred = ["coal", "charcoal", "birch_log", "oak_log", "birch_planks", "oak_planks"]) {
    for (const fname of preferred) {
      const item = mcData.itemsByName[fname];
      if (item && bot.inventory.findInventoryItem(item.id, null)) return fname;
    }
    return null;
  }

  // Helper: pick a random horizontal direction Vec3 for exploration
  function randomHorizontalDirection() {
    const opts = [
      new Vec3(1, 0, 0),
      new Vec3(-1, 0, 0),
      new Vec3(0, 0, 1),
      new Vec3(0, 0, -1),
      new Vec3(1, 0, 1),
      new Vec3(-1, 0, 1),
      new Vec3(1, 0, -1),
      new Vec3(-1, 0, -1),
    ];
    return opts[Math.floor(Math.random() * opts.length)];
  }

  // Helper: find a place position for placing blocks (tries global helper then fallback)
  async function findPlacePosition(radius) {
    try {
      if (typeof findNearbyOpenArea === "function") {
        const pos = await findNearbyOpenArea(bot, bot.entity ? bot.entity.position.floored() : null, radius);
        if (pos) return pos;
      }
    } catch (e) {
      // ignore and fallback
    }
    if (!bot.entity) throw new Error("Bot entity undefined; cannot determine placement position.");
    return bot.entity.position.floored().offset(1, 0, 0);
  }

  // Validation
  if (!bot) throw new Error("Bot instance required");
  if (!ingotType || typeof ingotType !== "string") throw new Error("ingotType string required");
  if (typeof targetCount !== "number" || targetCount <= 0) throw new Error("targetCount must be a positive number");

  const cfg = TYPE_MAP[ingotType] || {};
  const baseName = ingotType.replace(/_?ingot$/, "");
  const rawCandidates = cfg.rawNames && cfg.rawNames.length ? cfg.rawNames : [`raw_${baseName}`, `${baseName}_ore`];
  const oreCandidates = cfg.oreCandidates && cfg.oreCandidates.length ? cfg.oreCandidates : [`deepslate_${baseName}_ore`, `${baseName}_ore`];
  const useEnsureResource = !!cfg.useEnsureResource;
  const ensureResourceKey = cfg.ensureResourceKey || baseName;

  bot.chat && bot.chat(`Starting smeltIngots(${ingotType}): target ${targetCount}`);

  // 1) Determine how many ingots we already have
  const haveIngots = getItemCount(ingotType);
  if (haveIngots >= targetCount) {
    bot.chat && bot.chat(`I already have ${haveIngots} ${ingotType}(s). Nothing to do.`);
    return haveIngots;
  }
  let need = targetCount - haveIngots;
  bot.chat && bot.chat(`Need ${need} more ${ingotType}(s). Looking for raw material...`);

  // 2) Check how many raw items we already have (choose first present candidate)
  function findFirstRawInInventory() {
    for (const rn of rawCandidates) {
      if (getItemCount(rn) > 0) return rn;
    }
    return null;
  }

  let inputName = findFirstRawInInventory();
  let haveRaw = inputName ? getItemCount(inputName) : 0;

  if (haveRaw < need) {
    // If type requests ensureResource (like iron), try that first
    if (useEnsureResource && typeof ensureResource === "function") {
      bot.chat && bot.chat(`Attempting to obtain ${ensureResourceKey} resources via ensureResource...`);
      try {
        // Use the pattern seen in the iron variant: ensureResource(bot, count, 5, exploreTime, "iron")
        await ensureResource(bot, targetCount, 5, exploreTime, ensureResourceKey);
      } catch (e) {
        // ensureResource will have chatted details; continue to mining fallback if possible
        bot.chat && bot.chat(`ensureResource attempt failed or did not fully satisfy needs: ${e.message}`);
      }
      // re-evaluate inventory
      inputName = findFirstRawInInventory();
      haveRaw = inputName ? getItemCount(inputName) : 0;
    }

    // If still lacking and we have oreCandidates available, try to find and mine ore (gold-style)
    if (haveRaw < need) {
      // Look nearby first (maxDistance 32)
      let foundOreName = null;
      for (const oreName of oreCandidates) {
        const blockDef = mcData.blocksByName[oreName];
        if (!blockDef) continue;
        const blk = bot.findBlock({ matching: blockDef.id, maxDistance: 32 });
        if (blk) {
          foundOreName = oreName;
          break;
        }
      }

      // If none found nearby, explore in a random direction up to exploreTime (if exploreUntil helper exists)
      if (!foundOreName) {
        bot.chat && bot.chat(`No ${baseName} ore within 32 blocks. Exploring to find ore...`);
        if (typeof exploreUntil === "function") {
          const dir = randomHorizontalDirection();
          try {
            const found = await exploreUntil(bot, dir, exploreTime, () => {
              for (const oreName of oreCandidates) {
                const def = mcData.blocksByName[oreName];
                if (!def) continue;
                const b = bot.findBlock({ matching: def.id, maxDistance: 32 });
                if (b) return { name: oreName, block: b };
              }
              return null;
            });
            if (found) {
              foundOreName = found.name || (found.block && found.block.name);
            }
          } catch (e) {
            bot.chat && bot.chat(`Exploration for ${baseName} ore failed: ${e.message}`);
          }
        }
      }

      if (!foundOreName) {
        bot.chat && bot.chat(`No ${baseName} ore found nearby or during exploration. Will attempt other means if available.`);
      } else {
        bot.chat && bot.chat(`Found ore: ${foundOreName}. Mining up to ${need - haveRaw} ore(s)...`);
        const toMine = Math.max(0, need - haveRaw);
        if (toMine > 0) {
          try {
            const gained = await mineBlock(bot, foundOreName, toMine);
            await bot.waitForTicks(2);
            // After mining, re-evaluate which raw item we have
            inputName = findFirstRawInInventory();
            haveRaw = inputName ? getItemCount(inputName) : 0;
            bot.chat && bot.chat(`Mined ${gained} items of ${foundOreName}. Now have ${haveRaw} raw ${baseName} items.`);
          } catch (err) {
            bot.chat && bot.chat(`Failed to mine ${foundOreName}: ${err.message}`);
          }
        }
      }

      // One retry of exploration/mining if still short (mirror gold approach)
      if (haveRaw < need) {
        bot.chat && bot.chat(`Still need ${need - haveRaw} ${baseName} raw. Trying one more exploration attempt...`);
        if (typeof exploreUntil === "function") {
          const dir = randomHorizontalDirection();
          try {
            const found = await exploreUntil(bot, dir, exploreTime, () => {
              for (const oreName of oreCandidates) {
                const def = mcData.blocksByName[oreName];
                if (!def) continue;
                const b = bot.findBlock({ matching: def.id, maxDistance: 32 });
                if (b) return { name: oreName, block: b };
              }
              return null;
            });
            if (found) {
              const oreName = found.name || (found.block && found.block.name);
              try {
                const gained = await mineBlock(bot, oreName, Math.max(0, need - haveRaw));
                await bot.waitForTicks(2);
                inputName = findFirstRawInInventory();
                haveRaw = inputName ? getItemCount(inputName) : 0;
                bot.chat && bot.chat(`Second mining attempt gained ${gained}. Now have ${haveRaw} raw ${baseName}.`);
              } catch (err) {
                bot.chat && bot.chat(`Second mining attempt failed: ${err.message}`);
              }
            } else {
              bot.chat && bot.chat("Second exploration did not find additional ore.");
            }
          } catch (e) {
            bot.chat && bot.chat(`Second exploration error: ${e.message}`);
          }
        } else {
          bot.chat && bot.chat("No exploreUntil helper available; skipping second exploration attempt.");
        }
      }
    }
  }

  // Recompute how many to smelt and pick the inputName if multiple candidates exist
  inputName = findFirstRawInInventory();
  haveRaw = inputName ? getItemCount(inputName) : 0;
  const toSmelt = Math.min(need, haveRaw);

  if (toSmelt <= 0) {
    throw new Error(`Unable to obtain any raw material to smelt for ${ingotType}. Have ${haveRaw}, need ${need}.`);
  }

  // 4) Ensure a placed furnace is available within 32 blocks
  const furnaceBlockDef = mcData.blocksByName["furnace"];
  if (!furnaceBlockDef) throw new Error("This server version does not recognize 'furnace' in mcData.");
  let furnaceBlock = bot.findBlock({ matching: furnaceBlockDef.id, maxDistance: 32 });

  if (!furnaceBlock) {
    bot.chat && bot.chat("No placed furnace nearby. Will place one from inventory or craft one.");
    const furnaceItemDef = mcData.itemsByName["furnace"];
    if (!furnaceItemDef) throw new Error("This server version does not recognize 'furnace' item in mcData.");

    let haveFurnaceItem = bot.inventory.findInventoryItem(furnaceItemDef.id, null);
    if (!haveFurnaceItem) {
      bot.chat && bot.chat("No furnace item in inventory. Crafting a furnace...");
      try {
        await craftFurnace(bot, 1);
        await bot.waitForTicks(2);
        haveFurnaceItem = bot.inventory.findInventoryItem(furnaceItemDef.id, null);
        if (!haveFurnaceItem) throw new Error("Crafting furnace reported success but furnace not found in inventory.");
      } catch (err) {
        throw new Error(`Failed to craft a furnace: ${err.message}`);
      }
    } else {
      bot.chat && bot.chat("I have a furnace item.");
    }

    // Compute place position
    let placePos = null;
    try {
      placePos = await findPlacePosition(placeRadius || cfg.placeRadiusDefault || 6);
    } catch (e) {
      placePos = null;
    }
    if (!placePos) {
      if (!bot.entity) throw new Error("Bot entity undefined; cannot compute placement position.");
      placePos = bot.entity.position.floored().offset(1, 0, 0);
    }

    // Place furnace
    try {
      await placeItem(bot, "furnace", placePos);
      await bot.waitForTicks(4);
      furnaceBlock = bot.findBlock({ matching: furnaceBlockDef.id, maxDistance: 32 });
      if (!furnaceBlock) throw new Error("Placed furnace but cannot find it in the world.");
      bot.chat && bot.chat(`Placed furnace at ${furnaceBlock.position}.`);
    } catch (err) {
      throw new Error(`Failed to place furnace: ${err.message}`);
    }
  } else {
    bot.chat && bot.chat(`Found existing furnace at ${furnaceBlock.position}.`);
  }

  // 5) Choose fuel, attempt to obtain logs if needed (gold variant pattern)
  let fuelName = chooseFuel(["coal", "charcoal", "birch_log", "oak_log", "birch_planks", "oak_planks"]);
  if (!fuelName) {
    bot.chat && bot.chat("No common fuel found in inventory. Attempting to obtain logs...");
    try {
      // follow the gold pattern for obtaining logs (ensureResource signature used earlier for logs)
      if (typeof ensureResource === "function") {
        await ensureResource(bot, "logs", 1, 3, exploreTime);
      }
      fuelName = chooseFuel(["coal", "charcoal", "birch_log", "oak_log", "birch_planks", "oak_planks"]);
      if (!fuelName) throw new Error("After ensureResource, still no fuel found.");
    } catch (err) {
      throw new Error(`No fuel available and failed to obtain logs: ${err.message}`);
    }
  }
  bot.chat && bot.chat(`Using ${fuelName} as fuel.`);

  // 6) Perform smelting via smeltItem primitive
  try {
    await smeltItem(bot, inputName, fuelName, toSmelt);
    await bot.waitForTicks(4);
  } catch (err) {
    throw new Error(`Smelting failed: ${err.message}`);
  }

  // Final counts
  const finalIngots = getItemCount(ingotType);
  bot.chat && bot.chat(`Smelting complete. I now have ${finalIngots} ${ingotType}(s).`);
  return finalIngots;
}

