async function findCopperOre(bot, exploreTime = 60, maxDistance = 32) {
  // Matches original behavior: single exploration attempt and return null on not found
  return await findOre(bot, 'copper_ore', { maxTime: exploreTime, maxAttempts: 1, maxDistance, throwOnFail: false });
}

async function initMcDataVec3(bot) {
  // Self-contained initializer for mcData and Vec3
  // - Ensures the bot instance is present
  // - Loads minecraft-data for the bot.version
  // - Loads Vec3 from vec3
  if (!bot) throw new Error("Bot instance required");
  if (!bot.version) throw new Error("Bot.version is required to load minecraft-data");

  let mcData;
  let Vec3;
  try {
    mcData = require('minecraft-data')(bot.version);
  } catch (err) {
    throw new Error(`Failed to require minecraft-data for version ${bot.version}: ${err.message}`);
  }
  try {
    ({ Vec3 } = require('vec3'));
  } catch (err) {
    throw new Error(`Failed to require vec3: ${err.message}`);
  }

  if (!mcData) throw new Error(`minecraft-data returned falsy for version ${bot.version}`);
  if (!Vec3) throw new Error('Vec3 not available from vec3 package');

  return { mcData, Vec3 };
}

