async function ensureRawCopper(bot, targetTotal = 8, exploreTime = 60, maxAttempts = 3) {
    // This async routine ensures the bot collects a target number of raw_copper by first checking current inventory and verifying the bot entity exists; if there is a shortfall it repeatedly searches for copper ore up to a configurable number of attempts. When an ore block is located it equips the best available pickaxe and attempts to mine the needed amount, updating the inventory after mining. The loop continues until the desired total is reached or the maximum attempts are exhausted. If the target is met it returns the current count, otherwise it throws an error indicating failure.
}

nodes.code:
async function ensureRawCopper(bot, targetTotal = 8, exploreTime = 60, maxAttempts = 3) {
    // Updated: now calls findOre instead of findCopperOre

  // Obtain shared helpers (mcData, Vec3, getItemCount)
  const { mcData, Vec3, getItemCount } = await provideInventoryHelpers(bot);

  // Helper: pick best available pickaxe and equip it
  async function equipBestPickaxe() {
    const pref = ["diamond_pickaxe", "netherite_pickaxe", "iron_pickaxe", "stone_pickaxe", "wooden_pickaxe"];
    for (const name of pref) {
      const def = mcData.itemsByName[name];
      if (!def) continue;
      const slotItem = bot.inventory.findInventoryItem(def.id, null);
      if (slotItem) {
        try {
          await bot.equip(slotItem, "hand");
          bot.chat && bot.chat(`Equipped ${name} for mining.`);
          return true;
        } catch (e) {
          // continue trying others
        }
      }
    }
    return false;
  }

  // Helper: locate copper ore using the provided skill; returns null or a block
  async function locateCopper() {
    // findCopperOre is available in the global skills set
    try {
      const blk = await findOre(bot, exploreTime, 32, "copper_ore");
      return blk || null;
    } catch (e) {
      // bubble up as null so caller can retry
      return null;
    }
  }

  // Start main logic
  bot.chat && bot.chat(`ensureRawCopper: need ${targetTotal} raw_copper. Checking inventory...`);
  const rawName = "raw_copper";

  // Defensive: ensure bot.entity exists
  if (!bot.entity) {
    throw new Error("Bot entity undefined (dead/disconnected).");
  }

  let have = getItemCount(rawName);
  if (have >= targetTotal) {
    bot.chat && bot.chat(`Already have ${have}/${targetTotal} ${rawName}.`);
    return have;
  }

  let attempts = 0;
  while (attempts < maxAttempts && have < targetTotal) {
    attempts++;
    const need = targetTotal - have;
    bot.chat && bot.chat(`Attempt ${attempts}/${maxAttempts}: need ${need} more ${rawName}... Locating copper ore...`);

    const blk = await locateCopper();
    if (!blk) {
      bot.chat && bot.chat(`Could not find copper ore (attempt ${attempts}).`);
      // small delay before next attempt
      await bot.waitForTicks(10);
      continue;
    }

    // blk.name is important (deepslate_copper_ore vs copper_ore)
    const blockName = blk.name;
    bot.chat && bot.chat(`Found ${blockName} at ${blk.position}. Preparing to mine ${need} (delta).`);

    // Equip best pickaxe if possible (stone+ required for copper)
    await equipBestPickaxe();

    // Mine the needed delta. mineBlock expects a block-name string.
    try {
      const gained = await mineBlock(bot, blockName, need);
      // Wait for inventory sync
      await bot.waitForTicks(4);
      have = getItemCount(rawName);
      bot.chat && bot.chat(`Mining result: gained ${gained} ${rawName} (now have ${have}/${targetTotal}).`);
      if (have >= targetTotal) {
        bot.chat && bot.chat(`Success: have ${have} ${rawName}.`);
        return have;
      }
      // If gained was zero, loop will retry (findCopperOre may explore to other patches)
    } catch (err) {
      bot.chat && bot.chat(`Error mining ${blockName}: ${err.message}`);
      // wait a bit then retry
      await bot.waitForTicks(10);
    }
  }

  // Final check
  have = getItemCount(rawName);
  if (have >= targetTotal) {
    bot.chat && bot.chat(`Success after retries: have ${have} ${rawName}.`);
    return have;
  } else {
    const msg = `Failed to secure ${targetTotal} ${rawName} after ${attempts} attempts. Currently have ${have}.`;
    bot.chat && bot.chat(msg);
    throw new Error(msg);
  }
}

nodes.description:
async function craftPlanksAndPlaceChest(bot, chestCount = 1, preferredPlank = "birch_planks", placeRadius = 6) {
    // Validates inputs and calculates required planks (8 per chest), adding a 4‑plank reserve for a crafting table if no table block or item is present; it then checks inventory totals. If planks are missing it converts logs into planks as needed, ensures a placed crafting table exists (optionally preserving an existing crafting_table inventory item when a fifth boolean argument is true), and rechecks plank totals. Finally it crafts the requested number of chests and places up to that many chests at nearby open positions within the given radius, throwing errors if resources, the bot entity, or placement fail.
}

nodes.code:
async function craftPlanksAndPlaceChest(bot, chestCount = 1, preferredPlank = "birch_planks", placeRadius = 6) {
  /**
   * Ensures enough planks to craft `chestCount` chests, ensures a crafting table is placed,
   * crafts the chests and places them nearby.
   *
   * NOTE: To preserve any existing crafting_table inventory item (avoid consuming it when
   * placing a table), callers may pass an optional fifth argument (boolean) as preserveTableItem.
   * Example: craftPlanksAndPlaceChest(bot, 1, "birch_planks", 6, true)
   * This function does NOT change its declared signature; the flag is read via arguments[4].
   */

  // IMPORTANT: mcData and Vec3 must be declared first to avoid TDZ
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Read optional preserveTableItem flag from extra (fifth) argument if provided
  const preserveTableItem = typeof arguments[4] === "boolean" ? arguments[4] : false;

  // Helper: get total count of items by exact name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter((it) => it && it.name === name)
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Helper: get total planks (any variant) in inventory
  function getTotalPlanks() {
    return bot.inventory
      .items()
      .filter((it) => it && typeof it.name === "string" && it.name.endsWith("_planks"))
      .reduce((s, it) => s + it.count, 0);
  }

  // Helper: list log variants present in inventory (returns array of {logName, plankName, count})
  function listLogsInInventory() {
    const possibleLogs = [
      "oak_log",
      "spruce_log",
      "birch_log",
      "jungle_log",
      "acacia_log",
      "dark_oak_log",
      "mangrove_log",
      "cherry_log",
    ];
    const logs = [];
    for (const logName of possibleLogs) {
      const count = getItemCount(logName);
      if (count > 0) {
        // derive plank name by replacing '_log' -> '_planks'
        const plankName = logName.endsWith("_log") ? logName.replace(/_log$/, "_planks") : null;
        if (plankName && mcData.itemsByName[plankName]) {
          logs.push({ logName, plankName, count });
        } else {
          logs.push({ logName, plankName: null, count });
        }
      }
    }
    return logs;
  }

  // Helper: find a nearby open position for placement. Prefer global helper if present.
  async function findPlacePos(radius = placeRadius) {
    try {
      if (typeof findNearbyOpenArea === "function") {
        const pos = await findNearbyOpenArea(bot, bot.entity ? bot.entity.position.floored() : null, radius);
        if (pos) return pos;
      }
    } catch (e) {
      // ignore and fallback
    }
    if (!bot.entity) throw new Error("Bot entity undefined, cannot choose place position");
    const cand = bot.entity.position.floored().offset(2, 0, 0);
    if (cand.equals(bot.entity.position.floored()) || cand.equals(bot.entity.position.floored().offset(0, 1, 0))) {
      return bot.entity.position.floored().offset(2, 0, 0);
    }
    return cand;
  }

  // Begin main logic
  if (!bot) throw new Error("Bot instance required");
  if (typeof chestCount !== "number" || chestCount <= 0) throw new Error("chestCount must be a positive number");

  bot.chat(`Starting: craft ${chestCount} chest(s) and place them.`);

  // 1) determine required planks. Account for crafting_table cost if neither placed nor present.
  const planksPerChest = 8;
  let requiredPlanks = chestCount * planksPerChest;

  const craftingTableBlockDef = mcData.blocksByName["crafting_table"];
  if (!craftingTableBlockDef) {
    throw new Error("Server mcData does not recognize crafting_table.");
  }
  let placedTable = bot.findBlock({ matching: craftingTableBlockDef.id, maxDistance: 32 });
  const haveTableItemInitial = getItemCount("crafting_table");
  let reserveTablePlankCost = false;
  if (!placedTable && haveTableItemInitial <= 0) {
    // Reserve 4 planks for crafting_table so they are not consumed for chests
    requiredPlanks += 4;
    reserveTablePlankCost = true;
    bot.chat(
      `No crafting table (block/item) found. Reserving 4 planks for a crafting_table. Total required planks: ${requiredPlanks}.`,
    );
  }

  // 2) check current planks
  let totalPlanks = getTotalPlanks();
  bot.chat(`I currently have ${totalPlanks} planks (all variants). Need ${requiredPlanks}.`);

  // 3) if not enough, use specialized helper to convert logs into planks
  if (totalPlanks < requiredPlanks) {
    const missing = Math.max(0, requiredPlanks - getTotalPlanks());
    bot.chat(`I need ${missing} more planks. Attempting to craft via helper...`);
    if (missing > 0) {
      try {
        await craftBirchPlanks(
          bot,
          missing,
          { plankVariant: preferredPlank, logVariant: preferredPlank.replace(/_planks$/, "_log"), interpretAsDelta: true },
        );
      } catch (err) {
        bot.chat(`craftBirchPlanks failed: ${err && err.message ? err.message : String(err)}`);
        throw err;
      }
    }
    if (getTotalPlanks() < requiredPlanks) {
      throw new Error(`Failed to obtain required planks (${getTotalPlanks()}/${requiredPlanks}).`);
    }
  }

  bot.chat(`Have enough planks (${getTotalPlanks()}/${requiredPlanks}). Preparing crafting table...`);

  // 4) Ensure a placed crafting table exists (crafting_table block required for 3x3 recipes)
  placedTable = bot.findBlock({ matching: craftingTableBlockDef.id, maxDistance: 32 });
  if (!placedTable) {
    try {
      // If caller requested preservation of an existing crafting_table inventory item,
      // craft a separate crafting_table first so the existing inventory item is not consumed.
      const haveTableItemAtCall = getItemCount("crafting_table");
      if (preserveTableItem && haveTableItemAtCall > 0) {
        bot.chat(
          `preserveTableItem=true: will craft an extra crafting_table from planks so existing inventory item is preserved (inventory crafting_table before: ${haveTableItemAtCall}).`,
        );
        await craftCraftingTable(bot, 1, preferredPlank);
        try {
          await bot.waitForTicks(2);
        } catch (_) {}
      }

      bot.chat(
        `No placed crafting table found: will place one from inventory (crafting_table count: ${getItemCount("crafting_table")}).`,
      );

      // Call setupCraftingTable with the expected signature (bot, maxDistance). Do not pass preferredPlank.
      const placePos = await setupCraftingTable(bot, placeRadius);

      placedTable = bot.findBlock({ matching: craftingTableBlockDef.id, maxDistance: 32 });
      if (!placedTable) {
        throw new Error("Crafting table setup completed but block not found (possible chunk/visibility delay).");
      }
      bot.chat("Crafting table placed.");
    } catch (err) {
      bot.chat(`Failed to ensure crafting table: ${err.message}`);
      throw err;
    }
  } else {
    bot.chat(`Found placed crafting_table at ${placedTable.position}.`);
  }

  // After placing/crafting the table, recompute planks. Use helper again if still missing.
  totalPlanks = getTotalPlanks();
  bot.chat(`Planks after ensuring crafting table: ${totalPlanks}/${requiredPlanks}.`);
  if (totalPlanks < requiredPlanks) {
    const stillMissing = Math.max(0, requiredPlanks - getTotalPlanks());
    bot.chat(`Still missing ${stillMissing} planks after table creation. Attempting to craft via helper...`);
    if (stillMissing > 0) {
      try {
        await craftBirchPlanks(
          bot,
          stillMissing,
          { plankVariant: preferredPlank, logVariant: preferredPlank.replace(/_planks$/, "_log"), interpretAsDelta: true },
        );
      } catch (err) {
        bot.chat(`craftBirchPlanks failed on second pass: ${err && err.message ? err.message : String(err)}`);
        throw err;
      }
    }
    if (getTotalPlanks() < requiredPlanks) {
      throw new Error(`Insufficient planks after second conversion pass (${getTotalPlanks()}/${requiredPlanks}).`);
    }
  }

  // 5) Craft the chest(s)
  bot.chat(`Crafting ${chestCount} chest(s)...`);
  try {
    await craftItem(bot, "chest", chestCount);
    try {
      await bot.waitForTicks(2);
    } catch (_) {}
  } catch (err) {
    bot.chat(`Failed to craft chest(s): ${err.message}`);
    throw err;
  }

  // 6) Place chest(s)
  let chestsToPlace = chestCount;
  let haveChests = getItemCount("chest");
  if (haveChests <= 0) {
    bot.chat("No chest items found after crafting.");
    throw new Error("No chest items available to place.");
  }
  chestsToPlace = Math.min(chestCount, haveChests);

  bot.chat(`Placing ${chestsToPlace} chest(s) nearby...`);
  for (let i = 0; i < chestsToPlace; i++) {
    const pos = await findPlacePos(placeRadius);
    bot.chat(`Placing chest at ${pos.x},${pos.y},${pos.z}...`);
    try {
      await placeItem(bot, "chest", pos);
      try {
        await bot.waitForTicks(2);
      } catch (_) {}
    } catch (err) {
      bot.chat(`Failed to place chest at ${pos}: ${err.message}`);
      continue;
    }
  }

  bot.chat("Finished: crafted and placed chest(s).");
}

