async function makePlanksAndPlaceChest(
  bot,
  chestCount = 1,
  preferredPlank = "birch_planks",
  placeRadius = 6,
  keepPlanks = 0,
) {
  // MUST declare mcData and Vec3 first to avoid TDZ errors
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: total count of an item name in inventory


  // Helper: find any chest block within radius and return its position(s)
  function findChestsNearby(radius = placeRadius) {
    if (!bot.entity) return [];
    const center = bot.entity.position.floored();
    const found = [];
    for (let dx = -radius; dx <= radius; dx++) {
      for (let dy = -Math.min(6, radius); dy <= Math.min(6, radius); dy++) {
        for (let dz = -radius; dz <= radius; dz++) {
          const pos = center.offset(dx, dy, dz);
          const b = bot.blockAt(pos);
          if (b && b.name === "chest") found.push(b.position);
        }
      }
    }
    return found;
  }

  // Start
  if (!bot) throw new Error("Bot instance required");
  if (typeof chestCount !== "number" || chestCount <= 0) throw new Error("chestCount must be a positive number");

  bot.chat(
    `makePlanksAndPlaceChest: requested ${chestCount} chest(s). preferredPlank=${preferredPlank}, placeRadius=${placeRadius}, keepPlanks=${keepPlanks}`,
  );

  // planksPerChest = 8 (3x3 recipe uses 8 planks)
  const planksPerChest = 8;
  const requiredPlanksForChests = chestCount * planksPerChest;

  const currentPlanks = (() => {
    return bot.inventory
      .items()
      .filter((it) => it && typeof it.name === "string" && it.name.endsWith("_planks"))
      .reduce((s, it) => s + it.count, 0);
  })();

  // NOTE: Do NOT pre-craft chest-required materials here. Let craftPlanksAndPlaceChest
  // handle making exactly what it needs for crafting the table & chests.
  // We will call the child skill directly and then craft any leftover planks required by keepPlanks.

  // If we already have a crafting_table BLOCK placed nearby we won't consume planks to make one.
  const craftingTableBlockDef = mcData.blocksByName["crafting_table"];
  const placedTable = craftingTableBlockDef
    ? bot.findBlock({ matching: craftingTableBlockDef.id, maxDistance: 32 })
    : null;
  const hasPlacedTable = !!placedTable;
  bot.chat(`Current planks: ${currentPlanks}. Placed crafting table nearby: ${hasPlacedTable}`);

  // Call child skill to craft/place table and chests (child handles its own plank requirements)
  try {
    await craftPlanksAndPlaceChest(bot, chestCount, preferredPlank, placeRadius);
    await waitForInventorySync(bot, 2);
  } catch (err) {
    bot.chat(`craftPlanksAndPlaceChest failed: ${err.message}`);
    throw err;
  }

  // Recompute final planks and attempt to satisfy keepPlanks (post-check-and-craft)
  let finalPlanks = bot.inventory
    .items()
    .filter((it) => it && typeof it.name === "string" && it.name.endsWith("_planks"))
    .reduce((s, it) => s + it.count, 0);

  bot.chat(`After child: final planks=${finalPlanks}; requested keepPlanks=${keepPlanks}`);

  if (finalPlanks < keepPlanks) {
    const missing = keepPlanks - finalPlanks;
    const execs = Math.ceil(missing / 4); // each plank recipe execution yields 4 planks

    // Resolve a valid plank variant to craft
    let plankToCraft = preferredPlank;
    if (!mcData.itemsByName[plankToCraft]) {
      // fallback to any planks variant
      plankToCraft = Object.keys(mcData.itemsByName).find((n) => n.endsWith("_planks"));
      if (!plankToCraft) {
        throw new Error(`No plank variant known to server; cannot craft ${missing} planks to satisfy keepPlanks`);
      }
      bot.chat(`Preferred plank ${preferredPlank} unknown; falling back to ${plankToCraft}`);
    }

    bot.chat(`Crafting ${execs} recipe execution(s) of ${plankToCraft} to reach keepPlanks=${keepPlanks}`);
    // Let craftItem propagate errors so failure to meet keepPlanks is visible to caller
    await craftItem(bot, plankToCraft, execs);
    await waitForInventorySync(bot, 2);

    // Recompute final planks after crafting leftovers
    finalPlanks = bot.inventory
      .items()
      .filter((it) => it && typeof it.name === "string" && it.name.endsWith("_planks"))
      .reduce((s, it) => s + it.count, 0);

    if (finalPlanks < keepPlanks) {
      throw new Error(`Failed to obtain requested keepPlanks=${keepPlanks}. finalPlanks=${finalPlanks}`);
    }
  }

  const chestsFound = findChestsNearby(placeRadius);
  bot.chat(
    `Verification: final planks=${finalPlanks}; chests found within ${placeRadius} blocks = ${chestsFound.length}`,
  );

  if (chestsFound.length === 0) {
    throw new Error(
      `Completed craft/placement flow but could not find any chest within ${placeRadius} blocks. Try increasing placeRadius or ensuring there is an empty space to place into.`,
    );
  }

  bot.chat(`Success: found chest(s) at: ${chestsFound.map((p) => `(${p.x},${p.y},${p.z})`).join(", ")}`);
  return {
    finalPlanks,
    chests: chestsFound,
  };
}

