async function ensurePlanksThenCraftAndPlaceChest(bot, chestCount = 1, plankVariant = "birch_planks", placeRadius = 6, keepPlanks = 0) {
    // Validates inputs and computes how many planks are needed based on chestCount, plankVariant and keepPlanks, then ensures the bot has that many planks (crafting more if necessary). It ensures a usable crafting table is available, crafts the requested number of chests, and iteratively finds nearby valid placement positions within placeRadius to place each chest while tolerating common placement failures and polling for the chest block to appear. Finally it verifies final plank counts and nearby chests, warns if final planks are below keepPlanks, throws on fatal errors (insufficient resources, crafting table or no chests placed), and returns an object containing finalPlanks, placedChestPositions, and chestsFound.
}

