async function ensurePlanksThenCraftAndPlaceChest(
  bot,
  chestCount = 1,
  plankVariant = "birch_planks",
  placeRadius = 6,
  keepPlanks = 0,
) {
  // MUST declare mcData and Vec3 first to avoid TDZ errors
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: get total count of an item name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter((it) => it && it.name === name)
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Helper: find a nearby empty placement position within radius.
  // Now excludes bot's foot/head positions and requires at least one solid neighbor.
  async function findEmptyPlace(radius = placeRadius) {
    if (!bot.entity) throw new Error("Bot entity undefined; cannot find place position");
    const foot = bot.entity.position.floored();
    const head = foot.offset(0, 1, 0);

    const hasSolidNeighbor = (pos) => {
      const dirs = [new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1), new Vec3(0, -1, 0)];
      for (const d of dirs) {
        const n = bot.blockAt(pos.offset(d.x, d.y, d.z));
        if (n && n.boundingBox === "block") return true;
      }
      return false;
    };

    // Try optional helper if available
    try {
      if (typeof findNearbyOpenArea === "function") {
        const pos = await findNearbyOpenArea(bot, foot, radius);
        if (pos && !pos.equals(foot) && !pos.equals(head) && hasSolidNeighbor(pos)) return pos;
      }
    } catch (e) {
      // fallback to local search
    }

    const center = foot;
    for (let r = 1; r <= Math.max(2, radius); r++) {
      for (let dx = -r; dx <= r; dx++) {
        for (let dz = -r; dz <= r; dz++) {
          if (Math.abs(dx) !== r && Math.abs(dz) !== r) continue;
          const check = center.offset(dx, 0, dz);
          if (check.equals(foot) || check.equals(head)) continue;
          const block = bot.blockAt(check);
          const above = bot.blockAt(check.offset(0, 1, 0));
          const below = bot.blockAt(check.offset(0, -1, 0));
          if (
            block &&
            (block.name === "air" || block.name === "water") &&
            above &&
            (above.name === "air" || above.name === "water") &&
            below &&
            below.boundingBox === "block" &&
            hasSolidNeighbor(check)
          ) {
            return check;
          }
        }
      }
    }

    // fallback single offset (ensure not feet/head and has solid neighbor)
    let fallback = center.offset(1, 0, 0);
    if (fallback.equals(foot) || fallback.equals(head)) fallback = center.offset(2, 0, 0);
    if (!hasSolidNeighbor(fallback))
      throw new Error("No suitable nearby placement position with a solid neighbor was found");
    return fallback;
  }

  // VALIDATIONS
  if (!bot) throw new Error("Bot instance required");
  if (typeof chestCount !== "number" || chestCount <= 0) throw new Error("chestCount must be a positive number");
  if (typeof placeRadius !== "number" || placeRadius <= 0) placeRadius = 6;
  if (typeof keepPlanks !== "number" || keepPlanks < 0) keepPlanks = 0;

  bot.chat(
    `ensurePlanksThenCraftAndPlaceChest: request ${chestCount} chest(s), plankVariant=${plankVariant}, placeRadius=${placeRadius}, keepPlanks=${keepPlanks}`,
  );

  const planksPerChest = 8;
  const requiredPlanksForChests = chestCount * planksPerChest;
  const targetPlanksTotal = requiredPlanksForChests + keepPlanks;

  // record plank count before any work
  const plankPredicate = (it) => it && typeof it.name === "string" && it.name.endsWith("_planks");
  const plankCountBefore = bot.inventory
    .items()
    .filter(plankPredicate)
    .reduce((s, it) => s + it.count, 0);

  // If we don't have enough planks to both make chests and keep leftovers, craft planks.
  if (plankCountBefore < targetPlanksTotal) {
    const need = targetPlanksTotal - plankCountBefore;
    bot.chat(`Need ${need} more planks (target total ${targetPlanksTotal}). Delegating to craftBirchPlanks.`);
    // Derive a reasonable logVariant from plankVariant when possible (e.g. "birch_planks" -> "birch_log")
    let logVariantName = undefined;
    if (typeof plankVariant === "string" && plankVariant.endsWith("_planks")) {
      logVariantName = plankVariant.replace(/_planks$/, "_log");
    }
    try {
      // craftBirchPlanks accepts an options object in place of the plankVariant param.
      const plankCountAfterCraft = await craftBirchPlanks(bot, need, {
        plankVariant,
        logVariant: logVariantName,
        interpretAsDelta: true,
      });
      const gained = plankCountAfterCraft - plankCountBefore;
      if (gained <= 0) {
        throw new Error(
          `Plank crafting did not produce planks. Before=${plankCountBefore}, After=${plankCountAfterCraft}`,
        );
      }
    } catch (err) {
      const msg = err && err.message ? err.message : String(err);
      throw new Error(`craftBirchPlanks failed to produce required planks: ${msg}`);
    }
  } else {
    bot.chat(`Already have enough planks (${plankCountBefore}/${targetPlanksTotal}).`);
  }

  // Recompute available planks before chest workflow
  const plankCountNow = bot.inventory
    .items()
    .filter(plankPredicate)
    .reduce((s, it) => s + it.count, 0);
  bot.chat(`Planks now: ${plankCountNow}. Need ${requiredPlanksForChests} for ${chestCount} chest(s).`);

  if (plankCountNow < requiredPlanksForChests) {
    throw new Error(
      `Insufficient planks to craft ${chestCount} chest(s). Have ${plankCountNow}, need ${requiredPlanksForChests}.`,
    );
  }

  // Ensure a placed crafting table is available (craftItem needs it for 3x3 recipes)
  const craftingTableBlockDef = mcData.blocksByName["crafting_table"];
  let placedTable = craftingTableBlockDef
    ? bot.findBlock({ matching: craftingTableBlockDef.id, maxDistance: 32 })
    : null;
  if (!placedTable) {
    bot.chat("No placed crafting_table nearby. Ensuring one exists (may craft/place it).");
    // Use composable skill to create/place a usable table near the bot
    await setupCraftingTable(bot, placeRadius);

    // Poll for the placed crafting table to be visible to craftItem
    let found = null;
    for (let i = 0; i < 25; i++) {
      await bot.waitForTicks(2);
      found = bot.findBlock({ matching: craftingTableBlockDef.id, maxDistance: 32 });
      if (found) break;
    }
    if (!found) {
      // try direct blockAt for any candidate we may have placed (best-effort)
      bot.chat("Crafting table not found by findBlock after placement attempts. Checking immediate nearby blocks.");
      const center = bot.entity ? bot.entity.position.floored() : null;
      if (center) {
        for (let dx = -placeRadius; dx <= placeRadius && !found; dx++) {
          for (let dz = -placeRadius; dz <= placeRadius && !found; dz++) {
            for (let dy = -2; dy <= 2 && !found; dy++) {
              const b = bot.blockAt(center.offset(dx, dy, dz));
              if (b && b.type === craftingTableBlockDef.id) found = b;
            }
          }
        }
      }
    }
    if (!found)
      throw new Error("Crafting table placement reported success but block not found (possible chunk loading delay)");
    placedTable = found;
  } else {
    bot.chat(`Found placed crafting_table at ${placedTable.position}`);
  }

  // Craft chest(s)
  bot.chat(`Crafting ${chestCount} chest(s) now.`);
  const chestBefore = getItemCount("chest");
  await craftItem(bot, "chest", chestCount);
  await waitForInventorySync(bot, 2);
  const chestAfter = getItemCount("chest");
  const producedChests = chestAfter - chestBefore;
  if (producedChests < chestCount) {
    throw new Error(`Failed to craft the requested number of chests. Produced ${producedChests} of ${chestCount}`);
  }

  // Place chest(s) individually with placeItem so placements are recorded
  const placedChestPositions = [];
  for (let i = 0; i < chestCount; i++) {
    if (getItemCount("chest") <= 0) {
      bot.chat("No more chest items in inventory to place.");
      break;
    }
    let pos = await findEmptyPlace(placeRadius);
    // safety: ensure not placing on bot
    const foot = bot.entity.position.floored();
    const head = foot.offset(0, 1, 0);
    if (pos.equals(foot) || pos.equals(head)) pos = pos.offset(2, 0, 0);

    bot.chat(`Placing chest ${i + 1}/${chestCount} at ${pos.x},${pos.y},${pos.z}`);
    try {
      await placeItem(bot, "chest", pos);
    } catch (err) {
      const msg = String(err && err.message ? err.message : err);
      // Allow common placement failures to be retried at next location; rethrow unknown errors
      const recoverable = /blockUpdate|no valid reference|reference block|did not fire|no reference/i;
      if (recoverable.test(msg)) {
        bot.chat(`Placement failed at ${pos.x},${pos.y},${pos.z}: ${msg}. Trying next location.`);
        continue;
      }
      throw err; // unknown error - rethrow
    }

    // Poll until chest block is visible at the placement pos (best-effort, small timeout)
    let chestBlock = null;
    for (let t = 0; t < 25; t++) {
      await bot.waitForTicks(2);
      const b = bot.blockAt(pos);
      if (b && b.name === "chest") {
        chestBlock = b;
        break;
      }
    }
    if (chestBlock) {
      placedChestPositions.push(pos);
    } else {
      bot.chat(`Chest placement at ${pos.x},${pos.y},${pos.z} did not appear after timeout.`);
      // continue attempting next placements rather than aborting all
    }
  }

  // Final verification
  const finalPlanks = bot.inventory
    .items()
    .filter(plankPredicate)
    .reduce((s, it) => s + it.count, 0);
  const chestsFound = await findChestsNearby(bot, placeRadius);

  bot.chat(`Finished: final planks=${finalPlanks}; chests found within ${placeRadius} blocks = ${chestsFound.length}`);

  if (finalPlanks < keepPlanks) {
    bot.chat(`Warning: final planks (${finalPlanks}) < requested keepPlanks (${keepPlanks}).`);
  }

  if (placedChestPositions.length === 0 && chestsFound.length === 0) {
    throw new Error("No chests were placed or found after the operation.");
  }

  return {
    finalPlanks,
    placedChestPositions,
    chestsFound,
  };
}

