async function craftPlanksAndPlaceChestVerified(bot, chestCount = 1, plankVariant = "birch_planks", placeRadius = 6, keepPlanks = 0) {
    // This async routine ensures a given number of chests are present within a radius by first scanning nearby chests and, if there are too few, making sure a crafting table exists, producing any needed planks, crafting missing chest items, and attempting to place chests at nearby empty locations; it retries placement several times and verifies the results. If no chests are found after recovery attempts it throws an error; on success it returns the final plank count, the positions of chests it placed, and the list of chests found nearby.
}

nodes.code:
async function craftPlanksAndPlaceChestVerified(
  bot,
  chestCount = 1,
  plankVariant = "birch_planks",
  placeRadius = 6,
  keepPlanks = 0
) {
  // CRITICAL: declare mcData and Vec3 first to avoid TDZ
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: count items by exact name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter((it) => it && it.name === name)
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Helper: predicate for any plank variant
  function isPlankItem(it) {
    return it && typeof it.name === "string" && it.name.endsWith("_planks");
  }

  // Helper: find an empty place to put a block (requires a solid block beneath and space)
  async function findEmptyPlace(radius = placeRadius) {
    // Prefer global helper if available
    try {
      if (typeof findNearbyOpenArea === "function") {
        const pos = await findNearbyOpenArea(bot, bot.entity ? bot.entity.position.floored() : null, radius);
        if (pos) return pos;
      }
    } catch (_) {
      // ignore and fallback
    }

    if (!bot.entity) throw new Error("Bot entity undefined; cannot find place position");
    const center = bot.entity.position.floored();

    for (let r = 1; r <= Math.max(2, radius); r++) {
      for (let dx = -r; dx <= r; dx++) {
        for (let dz = -r; dz <= r; dz++) {
          // only edge positions to speed search
          if (Math.abs(dx) !== r && Math.abs(dz) !== r) continue;
          const check = center.offset(dx, 0, dz);
          // avoid bot feet/head
          if (check.equals(center) || check.equals(center.offset(0, 1, 0))) continue;
          const block = bot.blockAt(check);
          const above = bot.blockAt(check.offset(0, 1, 0));
          const below = bot.blockAt(check.offset(0, -1, 0));
          if (
            block &&
            (block.name === "air" || block.name === "water") &&
            above &&
            (above.name === "air" || above.name === "water") &&
            below &&
            below.boundingBox === "block"
          ) {
            return check;
          }
        }
      }
    }
    // fallback single offset (safe)
    let fallback = center.offset(2, 0, 0);
    if (fallback.equals(center) || fallback.equals(center.offset(0, 1, 0))) fallback = center.offset(3, 0, 0);
    return fallback;
  }

  // VALIDATION
  if (!bot) throw new Error("Bot instance required");
  if (typeof chestCount !== "number" || chestCount <= 0) throw new Error("chestCount must be a positive number");
  if (typeof placeRadius !== "number" || placeRadius <= 0) placeRadius = 6;
  if (typeof keepPlanks !== "number" || keepPlanks < 0) keepPlanks = 0;

  bot.chat(`Start: craft planks and place ${chestCount} chest(s).`);

  // Step 1: Try the existing composable skill that already handles planks/table/chests
  try {
    if (typeof ensurePlanksThenCraftAndPlaceChest === "function") {
      bot.chat("Using ensurePlanksThenCraftAndPlaceChest to perform main workflow...");
      try {
        await ensurePlanksThenCraftAndPlaceChest(bot, chestCount, plankVariant, placeRadius, keepPlanks);
      } catch (e) {
        // allow recovery attempts below if this throws
        bot.chat(`ensurePlanksThenCraftAndPlaceChest reported: ${e.message}`);
      }
      // small sync gap
      await bot.waitForTicks(4);
    } else {
      bot.chat("ensurePlanksThenCraftAndPlaceChest not available; continuing with manual flow.");
    }
  } catch (err) {
    bot.chat(`Error while calling ensurePlanksThenCraftAndPlaceChest: ${err.message}`);
  }

  // Step 2: verify chests
  let chestsFound = await findChestsNearby(bot, placeRadius);
  if (chestsFound.length >= chestCount) {
    bot.chat(`Verified: found ${chestsFound.length} chest(s) nearby.`);
    return {
      finalPlanks: bot.inventory.items().filter(isPlankItem).reduce((s, it) => s + it.count, 0),
      placedChestPositions: chestsFound.slice(0, chestCount),
      chestsFound,
    };
  }

  bot.chat(`Verification: found ${chestsFound.length}/${chestCount} chests. Attempting recovery placement.`);

  // RECOVERY: ensure a placed crafting table exists (craft/place if needed) because craftItem requires a table for 3x3
  const craftingTableDef = mcData.blocksByName["crafting_table"];
  let placedTable = craftingTableDef ? bot.findBlock({ matching: craftingTableDef.id, maxDistance: 32 }) : null;

  if (!placedTable) {
    bot.chat("No placed crafting_table detected. Ensuring inventory has one to place.");
    if (getItemCount("crafting_table") <= 0) {
      bot.chat("No crafting_table item in inventory. Crafting a crafting_table item (4 planks).");
      try {
        // craftCraftingTable is available in skills list
        if (typeof craftCraftingTable === "function") {
          await craftCraftingTable(bot, 1, plankVariant);
        } else {
          // fallback: craft via craftItem (2x2 recipe doesn't need placed table)
          await craftItem(bot, "crafting_table", 1);
        }
        await bot.waitForTicks(2);
      } catch (err) {
        bot.chat(`Failed to craft crafting_table item: ${err.message}`);
      }
    } else {
      bot.chat("Found crafting_table item in inventory.");
    }

    // place the crafting table
    try {
      const tablePos = await findEmptyPlace(placeRadius);
      bot.chat(`Placing crafting_table at ${tablePos.x},${tablePos.y},${tablePos.z}`);
      await placeItem(bot, "crafting_table", tablePos);
      await bot.waitForTicks(4);
      placedTable = craftingTableDef ? bot.findBlock({ matching: craftingTableDef.id, maxDistance: 32 }) : null;
      if (placedTable) bot.chat("Placed crafting_table for recovery.");
    } catch (err) {
      bot.chat(`Failed to place crafting_table during recovery: ${err.message}`);
    }
  } else {
    bot.chat(`Found placed crafting_table at ${placedTable.position}`);
  }

  // Step: ensure we have chest items to place; craft if needed
  // Integrated: ensure enough planks first via craftBirchPlanks, then craft chests as before
  try {
    const currentPlanks = bot.inventory.items().filter(isPlankItem).reduce((s, it) => s + it.count, 0);
    const neededPlanks = Math.max(0, chestCount * 8 - Math.max(keepPlanks, currentPlanks));
    if (neededPlanks > 0) {
      bot.chat(`Need ${neededPlanks} more planks to craft ${chestCount} chest(s). Ensuring planks via craftBirchPlanks...`);
      if (typeof craftBirchPlanks === "function") {
        try {
          // ask craftBirchPlanks to produce the missing planks as a delta and for the requested variant
          await craftBirchPlanks(bot, neededPlanks, { plankVariant: plankVariant, interpretAsDelta: true });
        } catch (err) {
          bot.chat(`craftBirchPlanks failed: ${err.message}`);
        }
      } else {
        bot.chat("craftBirchPlanks not available; continuing without delegated plank crafting.");
      }
    }
  } catch (err) {
    bot.chat(`Error while ensuring planks via craftBirchPlanks: ${err.message}`);
  }

  let chestItems = getItemCount("chest");
  if (chestItems < chestCount) {
    bot.chat(`Need ${chestCount - chestItems} chest item(s). Crafting now.`);
    try {
      // craftItem requires a placed crafting table for 3x3; ensure placedTable exists, but craftItem will handle 2x2/3x3 logic
      await craftItem(bot, "chest", chestCount - chestItems);
      await bot.waitForTicks(2);
    } catch (err) {
      bot.chat(`Failed to craft chest(s): ${err.message}`);
    }
    chestItems = getItemCount("chest");
  }

  // Step: place chest items explicitly at empty locations
  const placedChestPositions = [];
  let attempts = 0;
  const maxAttempts = Math.max(4, chestCount * 3);
  while (placedChestPositions.length < chestCount && attempts < maxAttempts) {
    attempts++;
    chestItems = getItemCount("chest");
    if (chestItems <= 0) {
      bot.chat("No chest items left to place during recovery.");
      break;
    }
    const pos = await findEmptyPlace(placeRadius);
    bot.chat(`Recovery placement attempt ${attempts}: placing chest at ${pos.x},${pos.y},${pos.z}`);
    try {
      await placeItem(bot, "chest", pos);
      await bot.waitForTicks(3);
      // verify block is chest
      const block = bot.blockAt(pos);
      if (block && block.name === "chest") {
        placedChestPositions.push(pos);
        bot.chat(`Placed chest at ${pos.x},${pos.y},${pos.z}`);
      } else {
        bot.chat(`Placement reported but no chest block found at ${pos.x},${pos.y},${pos.z}`);
      }
    } catch (err) {
      bot.chat(`Failed to place chest at ${pos.x},${pos.y},${pos.z}: ${err.message}`);
      // try different spot next loop
    }
  }

  // Final verification scan
  await bot.waitForTicks(4);
  chestsFound = await findChestsNearby(bot, placeRadius);

  if (chestsFound.length === 0) {
    const finalPlanks = bot.inventory.items().filter(isPlankItem).reduce((s, it) => s + it.count, 0);
    bot.chat("Recovery failed: no chests found after attempts.");
    throw new Error(
      `Failed to place any chest within ${placeRadius} blocks. Final planks=${finalPlanks}. ` +
        `Tried placing ${placedChestPositions.length} chest(s).`
    );
  }

  bot.chat(`Recovery success: found ${chestsFound.length} chest(s) nearby.`);

  return {
    finalPlanks: bot.inventory.items().filter(isPlankItem).reduce((s, it) => s + it.count, 0),
    placedChestPositions,
    chestsFound,
  };
}

async function getNearbyChests(bot, radius = 6) {
  // Self-contained helper: find chest blocks within radius around the bot
  // Returns an array of Vec3 positions (may be empty). Does not rely on any external helper.
  if (!bot) throw new Error("Bot instance required");
  if (!bot.entity) return [];

  // Ensure radius is a number
  if (typeof radius !== 'number' || !isFinite(radius) || radius < 0) radius = 6;

  const center = bot.entity.position.floored();
  const found = [];
  for (let dx = -radius; dx <= radius; dx++) {
    for (let dy = -Math.min(6, radius); dy <= Math.min(6, radius); dy++) {
      for (let dz = -radius; dz <= radius; dz++) {
        const pos = center.offset(dx, dy, dz);
        const b = bot.blockAt(pos);
        if (b && b.name === "chest") found.push(b.position);
      }
    }
  }
  return found;
}

async function depositUselessItems(bot, chestPosition = null, minCount = 16, extraBlacklist = []) {
  // CRITICAL: declare mcData / Vec3 FIRST to avoid TDZ
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: convert potential plain object to Vec3
  function toVec3(pos) {
    if (!pos) return null;
    if (pos instanceof Vec3) return pos;
    if (typeof pos.x === "number" && typeof pos.y === "number" && typeof pos.z === "number") {
      return new Vec3(pos.x, pos.y, pos.z);
    }
    return null;
  }

  // Helper: build a map of total counts by item name
  function getInventoryCounts() {
    const counts = {};
    for (const it of bot.inventory.items()) {
      if (!it || !it.name) continue;
      counts[it.name] = (counts[it.name] || 0) + it.count;
    }
    return counts;
  }

  // Validation
  if (!bot) throw new Error("Bot instance required");

  bot.chat("Preparing to deposit useless items into chest...");

  // Resolve chest block
  let chestBlock = null;
  const chestVec = toVec3(chestPosition);
  if (chestVec) {
    chestBlock = bot.blockAt(chestVec);
    if (!chestBlock || chestBlock.name !== "chest") {
      bot.chat(`No chest block found at provided position (${chestVec.x},${chestVec.y},${chestVec.z}). Searching nearby instead...`);
      chestBlock = null;
    }
  }

  if (!chestBlock) {
    const chestDef = mcData.blocksByName["chest"];
    if (!chestDef) throw new Error("Server mcData does not recognize 'chest'");
    // Find a chest within 32 blocks per rules
    chestBlock = bot.findBlock({ matching: chestDef.id, maxDistance: 32 });
    if (!chestBlock) {
      throw new Error("No chest found within 32 blocks. Place or move to a chest first.");
    }
  }

  bot.chat(`Using chest at ${chestBlock.position.x}, ${chestBlock.position.y}, ${chestBlock.position.z}`);

  // Default blacklist (do NOT deposit these by default)
  const defaultKeep = new Set([
    // valuable items / tools / functional blocks
    "diamond", "diamond_pickaxe",
    "iron_pickaxe", "wooden_pickaxe", "stone_pickaxe", "wooden_axe",
    "iron_ingot", "gold_ingot", "diamond_hoe", "diamond_sword",
    "crafting_table", "furnace", "chest", "birch_log", "birch_planks",
    "birch_sapling", "stick", "apple", "mushroom"
  ]);
  for (const n of extraBlacklist) defaultKeep.add(n);

  // Build itemsToDeposit: map name -> count to deposit
  const counts = getInventoryCounts();
  const itemsToDeposit = {};
  for (const [name, total] of Object.entries(counts)) {
    // Skip if blacklisted / in keep set
    if (defaultKeep.has(name)) continue;
    // Skip non-stackable items (tools usually have count 1)
    // We consider "stackable" as total > 1 (safe heuristic)
    if (total < minCount) continue;
    // Finally include this item: deposit the whole amount by default
    itemsToDeposit[name] = total;
  }

  if (Object.keys(itemsToDeposit).length === 0) {
    bot.chat(`Nothing meets the deposit criteria (minCount=${minCount}). No items deposited.`);
    return { deposited: {}, chest: chestBlock.position };
  }

  // Announce what we'll deposit
  bot.chat(`Depositing items into chest: ${Object.entries(itemsToDeposit).map(([n,c])=>`${n} x${c}`).join(", ")}`);

  // Use existing global skill depositItemIntoChest(bot, chestPosition, itemsToDeposit)
  try {
    await depositItemIntoChest(bot, chestBlock.position, itemsToDeposit);
    bot.chat("Deposit complete.");
    return { deposited: itemsToDeposit, chest: chestBlock.position };
  } catch (err) {
    bot.chat(`Failed to deposit items: ${err.message}`);
    throw err;
  }
}

