async function depositUselessItemsSafe(bot, chestPosition = null, minCount = 16, extraBlacklist = [], maxChestTries = 5) {
  // MUST declare mcData and Vec3 FIRST to avoid TDZ
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: convert potential plain object to Vec3
  function toVec3(pos) {
    if (!pos) return null;
    if (pos instanceof Vec3) return pos;
    if (typeof pos.x === "number" && typeof pos.y === "number" && typeof pos.z === "number") {
      return new Vec3(pos.x, pos.y, pos.z);
    }
    return null;
  }

  // Helper: build a map of total counts by item name
  function getInventoryCounts() {
    const counts = {};
    for (const it of bot.inventory.items()) {
      if (!it || !it.name) continue;
      counts[it.name] = (counts[it.name] || 0) + it.count;
    }
    return counts;
  }

  // Validation
  if (!bot) throw new Error("Bot instance required");

  bot.chat("Preparing to deposit useless items into chest (robust mode)...");

  // Build deposit list (default keep set + extra blacklist)
  const defaultKeep = new Set([
    "diamond", "diamond_pickaxe",
    "iron_pickaxe", "wooden_pickaxe", "stone_pickaxe", "wooden_axe",
    "iron_ingot", "gold_ingot", "diamond_hoe", "diamond_sword",
    "crafting_table", "furnace", "chest", "birch_log", "birch_planks",
    "birch_sapling", "stick", "apple", "mushroom"
  ]);
  for (const n of extraBlacklist) defaultKeep.add(n);

  const counts = getInventoryCounts();
  const itemsToDeposit = {};
  for (const [name, total] of Object.entries(counts)) {
    if (defaultKeep.has(name)) continue;
    if (total < minCount) continue;
    itemsToDeposit[name] = total;
  }

  if (Object.keys(itemsToDeposit).length === 0) {
    bot.chat(`Nothing meets the deposit criteria (minCount=${minCount}). No items deposited.`);
    return { deposited: {}, chest: null };
  }

  bot.chat(`Will attempt to deposit: ${Object.entries(itemsToDeposit).map(([n,c])=>`${n} x${c}`).join(", ")}`);

  // Resolve chest candidates
  const chestDef = mcData.blocksByName["chest"];
  if (!chestDef) throw new Error("Server mcData does not recognize 'chest'");

  const tried = [];
  const errors = [];

  // If user provided a chestPosition, try it first
  const userChestVec = toVec3(chestPosition);
  const candidates = [];

  if (userChestVec) candidates.push(userChestVec);

  // find other chests within 32 blocks (limit to some reasonable count)
  try {
    const foundPositions = bot.findBlocks({
      matching: chestDef.id,
      maxDistance: 32,
      count: 64
    }); // may return []
    if (Array.isArray(foundPositions)) {
      for (const pos of foundPositions) {
        const v = toVec3(pos);
        if (!v) continue;
        // avoid duplicate of user-specified
        if (userChestVec && v.equals(userChestVec)) continue;
        candidates.push(v);
      }
    }
  } catch (e) {
    // findBlocks can fail in some contexts; ignore and proceed with any user chest
  }

  if (candidates.length === 0) {
    throw new Error("No chest found within 32 blocks (and no chestPosition provided). Place or move to a chest first.");
  }

  // Trim candidates to maxChestTries
  while (candidates.length > maxChestTries) candidates.pop();

  // Try each candidate in sequence
  for (let i = 0; i < candidates.length; i++) {
    const chestPos = candidates[i];
    tried.push(chestPos);
    bot.chat(`Attempting deposit into chest at ${chestPos.x}, ${chestPos.y}, ${chestPos.z} (try ${i+1}/${candidates.length})`);
    try {
      // Use existing skill depositItemIntoChest (it handles moveToChest/opening/withdrawing)
      await depositItemIntoChest(bot, chestPos, itemsToDeposit);
      bot.chat(`Deposit complete into chest at ${chestPos.x}, ${chestPos.y}, ${chestPos.z}`);
      return { deposited: itemsToDeposit, chest: chestPos };
    } catch (err) {
      // Record and continue to next candidate
      const msg = err && err.message ? err.message : String(err);
      errors.push({ pos: chestPos, error: msg });
      bot.chat(`Failed to deposit into chest at ${chestPos.x}, ${chestPos.y}, ${chestPos.z}: ${msg}`);
      // small delay before next attempt
      try { await new Promise(r => setTimeout(r, 1000)); } catch (_) {}
    }
  }

  // As a last resort, try teleporting to the first candidate (if not already at it) and retry once
  const first = candidates[0];
  if (first && bot.entity && bot.entity.position.distanceTo(first) > 4) {
    bot.chat(`All nearby chests failed. Trying a forced teleport to ${first.x},${first.y},${first.z} and retrying once.`);
    try {
      bot.chat(`/tp ${first.x} ${first.y} ${first.z}`);
      // give server a moment to teleport and sync
      await new Promise(r => setTimeout(r, 2000));
      try {
        await depositItemIntoChest(bot, first, itemsToDeposit);
        bot.chat(`Deposit complete into chest at ${first.x}, ${first.y}, ${first.z} after teleport.`);
        return { deposited: itemsToDeposit, chest: first };
      } catch (err) {
        const msg = err && err.message ? err.message : String(err);
        errors.push({ pos: first, error: `post-teleport: ${msg}` });
        bot.chat(`Retry after teleport failed: ${msg}`);
      }
    } catch (tpErr) {
      // continue to final failure
      errors.push({ pos: first, error: `teleport failed: ${tpErr.message}` });
      bot.chat(`Teleport attempt failed: ${tpErr.message}`);
    }
  }

  // If we reached here, we failed all attempts
  const summary = errors.map(e => `at ${e.pos.x},${e.pos.y},${e.pos.z} -> ${e.error}`).join("; ");
  const fullMsg = `Failed to deposit items into any candidate chest. Attempts: ${tried.length}. Errors: ${summary}`;
  bot.chat(fullMsg);
  throw new Error(fullMsg);
}

