async function ensureCoalOrCharcoal(bot, targetCount = 8, exploreTime = 60) {
  // MUST declare mcData and Vec3 FIRST to avoid TDZ errors
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: total count of an item by name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory.items()
      .filter(it => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Helper: total coal+charcoal
  function getCoalTotal() {
    return getItemCount("coal") + getItemCount("charcoal");
  }

  // Helper: find nearest coal ore block (coal_ore or deepslate_coal_ore) within 32
  function findNearbyCoalOre() {
    const coal = mcData.blocksByName["coal_ore"];
    const dcoal = mcData.blocksByName["deepslate_coal_ore"];
    if (!coal && !dcoal) return null;
    return bot.findBlock({
      matching: block => {
        if (!block) return false;
        return (coal && block.type === coal.id) || (dcoal && block.type === dcoal.id);
      },
      maxDistance: 32
    });
  }

  // Helper: choose best pickaxe available in inventory (prefer diamond > netherite > iron > stone)
  function chooseBestPickaxe() {
    const pref = ["diamond_pickaxe", "netherite_pickaxe", "iron_pickaxe", "stone_pickaxe"];
    for (const name of pref) {
      const item = mcData.itemsByName[name];
      if (!item) continue;
      const found = bot.inventory.findInventoryItem(item.id, null);
      if (found) return found;
    }
    return null;
  }

  // Helper: find any log name present in inventory (returns string name)
  function findAnyLogInInventory() {
    const items = bot.inventory.items();
    for (const it of items) {
      if (!it || !it.name) continue;
      if (it.name.endsWith("_log")) return it.name;
    }
    return null;
  }

  // Helper: find a nearby placed furnace block within 32 blocks
  function findNearbyFurnaceBlock() {
    const furnaceDef = mcData.blocksByName["furnace"];
    if (!furnaceDef) return null;
    return bot.findBlock({ matching: furnaceDef.id, maxDistance: 32 });
  }

  // Helper: choose a reasonable fuel from inventory for smelting (ordered preference)
  function chooseFuelForSmelt() {
    const prefer = ["coal", "charcoal", "birch_planks", "oak_planks", "spruce_planks", "jungle_planks", "acacia_planks", "dark_oak_planks", "stick", "birch_log", "oak_log"];
    for (const name of prefer) {
      const it = mcData.itemsByName[name];
      if (!it) continue;
      if (bot.inventory.findInventoryItem(it.id, null)) return name;
    }
    return null;
  }

  // Helper: find logs in the world (any *_log) within 32 blocks
  function findNearbyLogBlock() {
    const logNames = Object.keys(mcData.blocksByName).filter(n => n.endsWith("_log"));
    const ids = logNames.map(n => mcData.blocksByName[n].id);
    return bot.findBlock({ matching: ids, maxDistance: 32 });
  }

  // Start main logic
  if (!bot) throw new Error("Bot instance required");

  bot.chat && bot.chat(`Ensuring ${targetCount} coal/charcoal...`);

  // 1) Fast check current coal/charcoal
  let have = getCoalTotal();
  bot.chat && bot.chat(`Currently have ${have} (coal+charcoal).`);
  if (have >= targetCount) {
    bot.chat && bot.chat(`Already have ${have} (>= ${targetCount}).`);
    return have;
  }
  let need = targetCount - have;

  // 2) Try to find and mine coal ore (single nearby search then optionally explore)
  let coalBlock = findNearbyCoalOre();
  if (!coalBlock) {
    bot.chat && bot.chat("No coal ore within 32 blocks. Will explore briefly to look for coal ore...");
    // Use a single exploreUntil call with a callback that checks both variants
    const directions = [new Vec3(1,0,0), new Vec3(-1,0,0), new Vec3(0,0,1), new Vec3(0,0,-1), new Vec3(1,0,1), new Vec3(-1,0,1), new Vec3(1,0,-1), new Vec3(-1,0,-1)];
    const dir = directions[Math.floor(Math.random() * directions.length)];
    try {
      const foundDuringExplore = await exploreUntil(bot, dir, exploreTime, () => {
        return findNearbyCoalOre() || null;
      });
      // exploreUntil returns whatever the callback returned; we used findNearbyCoalOre so check again
      coalBlock = findNearbyCoalOre();
      if (coalBlock) bot.chat && bot.chat(`Found coal ore at ${coalBlock.position} during exploration.`);
    } catch (e) {
      bot.chat && bot.chat(`Exploration for coal ore failed: ${e.message}`);
    }
  } else {
    bot.chat && bot.chat(`Found coal ore nearby at ${coalBlock.position}.`);
  }

  if (coalBlock) {
    // Equip best pickaxe if available
    const best = chooseBestPickaxe();
    if (best) {
      try {
        await bot.equip(best, "hand");
        bot.chat && bot.chat(`Equipped ${mcData.items[best.type].name} for mining.`);
      } catch (e) {
        bot.chat && bot.chat(`Failed to equip pickaxe: ${e.message}`);
      }
    } else {
      bot.chat && bot.chat("No pickaxe found in inventory; attempting to mine with whatever is held.");
    }

    // Mine the coal ore. mineBlock expects a BLOCK NAME string.
    const blockName = coalBlock.name; // 'coal_ore' or 'deepslate_coal_ore'
    try {
      bot.chat && bot.chat(`Mining up to ${need} ${blockName}(s)...`);
      const gained = await mineBlock(bot, blockName, need);
      await bot.waitForTicks(2);
      have = getCoalTotal();
      need = targetCount - have;
      bot.chat && bot.chat(`Mined. Gained ~${gained}. Now have ${have} (need ${Math.max(0, need)}).`);
      if (have >= targetCount) {
        bot.chat && bot.chat(`Success: obtained ${have} coal/charcoal.`);
        return have;
      }
    } catch (err) {
      bot.chat && bot.chat(`Mining coal ore failed: ${err.message}`);
    }
  } else {
    bot.chat && bot.chat("No coal ore found after explore or mining attempts.");
  }

  // 3) Fallback: make charcoal by smelting logs

  // Determine how many charcoal still needed
  have = getCoalTotal();
  need = targetCount - have;
  if (need <= 0) {
    bot.chat && bot.chat(`Already satisfied after mining: ${have}.`);
    return have;
  }
  bot.chat && bot.chat(`Will attempt to produce ${need} charcoal by smelting logs.`);

  // Choose which log type to smelt: prefer logs present in inventory, else will collect logs
  let logName = findAnyLogInInventory(); // e.g., 'birch_log'
  let totalLogs = 0;
  // compute total logs in inventory
  const items = bot.inventory.items();
  for (const it of items) {
    if (it && it.name && it.name.endsWith("_log")) totalLogs += it.count;
  }

  // If insufficient logs in inventory, try to collect logs in the world
  if (totalLogs < need) {
    bot.chat && bot.chat(`Only have ${totalLogs} logs in inventory; need ${need}. Searching for logs nearby...`);
    let logBlock = findNearbyLogBlock();
    if (!logBlock) {
      bot.chat && bot.chat("No log blocks found within 32 blocks. Exploring to find trees...");
      // pick a random horizontal direction for exploration
      const directions = [new Vec3(1,0,0), new Vec3(-1,0,0), new Vec3(0,0,1), new Vec3(0,0,-1), new Vec3(1,0,1), new Vec3(-1,0,1), new Vec3(1,0,-1), new Vec3(-1,0,-1)];
      const dir = directions[Math.floor(Math.random() * directions.length)];
      try {
        const found = await exploreUntil(bot, dir, exploreTime, () => {
          return findNearbyLogBlock() || null;
        });
        logBlock = findNearbyLogBlock();
        if (logBlock) bot.chat && bot.chat(`Found logs at ${logBlock.position} while exploring.`);
      } catch (e) {
        bot.chat && bot.chat(`Exploration for logs failed: ${e.message}`);
      }
    } else {
      bot.chat && bot.chat(`Found logs nearby at ${logBlock.position}.`);
    }

    if (logBlock) {
      // Mine enough logs (DELTA semantics: pass how many additional logs to get)
      const toMine = Math.max(need - totalLogs, 1);
      try {
        bot.chat && bot.chat(`Mining ${toMine} ${logBlock.name}(s)...`);
        const gained = await mineBlock(bot, logBlock.name, toMine);
        await bot.waitForTicks(2);
        // Recalculate totals
        totalLogs = 0;
        for (const it of bot.inventory.items()) {
          if (it && it.name && it.name.endsWith("_log")) totalLogs += it.count;
        }
        logName = findAnyLogInInventory();
        bot.chat && bot.chat(`Mining logs done. Now have ${totalLogs} logs (need ${need}).`);
      } catch (err) {
        bot.chat && bot.chat(`Failed to mine logs: ${err.message}`);
      }
    } else {
      bot.chat && bot.chat("Could not find any logs to mine.");
    }
  } else {
    logName = findAnyLogInInventory();
    bot.chat && bot.chat(`Have ${totalLogs} logs in inventory, will use ${logName} for smelting.`);
  }

  // Recompute how many to smelt
  have = getCoalTotal();
  need = targetCount - have;
  if (need <= 0) {
    bot.chat && bot.chat(`Already satisfied: ${have}.`);
    return have;
  }

  // Determine how many logs available to smelt
  const availableLogs = (() => {
    let t = 0;
    for (const it of bot.inventory.items()) {
      if (it && it.name && it.name.endsWith("_log")) t += it.count;
    }
    return t;
  })();

  if (availableLogs <= 0) {
    throw new Error(`No logs available to smelt into charcoal. Found ${availableLogs}.`);
  }

  // Number of logs to smelt (can't smelt more than available)
  const toSmelt = Math.min(need, availableLogs);
  if (!logName) logName = findAnyLogInInventory();
  if (!logName) throw new Error("No log type found in inventory for smelting.");

  // Ensure a furnace is placed
  let furnaceBlock = findNearbyFurnaceBlock();
  if (!furnaceBlock) {
    bot.chat && bot.chat("No placed furnace nearby. Will place one from inventory or craft one.");
    // If we don't have a furnace item in inventory, craft one
    const furnaceItemDef = mcData.itemsByName["furnace"];
    if (!furnaceItemDef) throw new Error("This server version does not recognize 'furnace' in mcData.");
    let haveFurnaceItem = bot.inventory.findInventoryItem(furnaceItemDef.id, null);
    if (!haveFurnaceItem) {
      bot.chat && bot.chat("No furnace item in inventory. Crafting a furnace...");
      await craftFurnace(bot, 1);
      await bot.waitForTicks(2);
      haveFurnaceItem = bot.inventory.findInventoryItem(furnaceItemDef.id, null);
      if (!haveFurnaceItem) throw new Error("Failed to craft a furnace item.");
    }

    // Find position to place furnace
    let placePos = null;
    try {
      if (typeof findNearbyOpenArea === "function") {
        placePos = await findNearbyOpenArea(bot, bot.entity ? bot.entity.position.floored() : null, 6);
      }
    } catch (e) {
      placePos = null;
    }
    if (!placePos) {
      if (!bot.entity) throw new Error("Bot entity undefined; cannot determine placement position.");
      placePos = bot.entity.position.floored().offset(1, 0, 0);
    }

    try {
      await placeItem(bot, "furnace", placePos);
      await bot.waitForTicks(4);
      furnaceBlock = findNearbyFurnaceBlock();
      if (!furnaceBlock) throw new Error("Placed furnace but cannot find it in the world.");
      bot.chat && bot.chat(`Placed furnace at ${furnaceBlock.position}.`);
    } catch (err) {
      bot.chat && bot.chat(`Failed to place furnace: ${err.message}`);
      throw err;
    }
  } else {
    bot.chat && bot.chat(`Found furnace at ${furnaceBlock.position}.`);
  }

  // Choose fuel for smelting
  let fuel = chooseFuelForSmelt();
  if (!fuel) {
    bot.chat && bot.chat("No obvious fuel (coal/charcoal/planks/stick) found in inventory. Trying to use some logs as fuel (less efficient).");
    // If absolutely nothing else, use logs as fuel (but that uses logs we might want to smelt)
    fuel = findAnyLogInInventory();
    if (!fuel) throw new Error("No fuel available to smelt logs into charcoal.");
  }
  bot.chat && bot.chat(`Using ${fuel} as fuel to smelt ${toSmelt} ${logName}(s) into charcoal.`);

  // Smelt logs into charcoal: smeltItem(inputName, fuelName, count)
  try {
    await smeltItem(bot, logName, fuel, toSmelt);
    await bot.waitForTicks(4);
  } catch (err) {
    bot.chat && bot.chat(`Smelting failed: ${err.message}`);
    throw err;
  }

  // Final count
  have = getCoalTotal();
  if (have >= targetCount) {
    bot.chat && bot.chat(`Success: now have ${have} coal/charcoal.`);
    return have;
  } else {
    const deficit = targetCount - have;
    throw new Error(`Unable to reach target. Now have ${have}, need ${deficit} more. Check resources (logs/fuel) and environment.`);
  }
}

nodes.description:
async function craftDiamondBoots(bot, count = 1, options = {}) {
    // This async routine crafts a requested number of diamond boots using the bot's inventory and server item data. It validates the bot instance and that count is a positive number, confirms the "diamond_boots" item exists for the server version, and checks the inventory has enough diamonds (4 diamonds per boots) or throws an error. Because the recipe requires a 3x3 crafting table, it ensures a crafting_table block is present within range and, if missing, will attempt to obtain and place one near the bot by choosing a safe nearby position and failing with clear errors if placement or obtaining the table is not possible. Once a crafting table is available it performs the 3x3 craft for the requested count, waits briefly for inventory updates, verifies how many diamond boots are present, and returns that final count.
}

nodes.code:
async function craftDiamondBoots(bot, count = 1, options = {}) {
  // Obtain shared helpers (mcData, Vec3, getItemCount)
  const { mcData, Vec3, getItemCount } = await provideInventoryHelpers(bot);

  // Begin main logic
  if (!bot) throw new Error("Bot instance required");
  if (typeof count !== "number" || count <= 0) {
    throw new Error("count must be a positive number");
  }

  const itemName = "diamond_boots";
  const itemDef = mcData.itemsByName[itemName];
  if (!itemDef) {
    throw new Error(`${itemName} is not recognized by mcData for this server version.`);
  }

  const diamondsNeeded = 4 * count;
  const haveDiamonds = getItemCount("diamond");
  if (bot.chat) bot.chat(`Need ${diamondsNeeded} diamonds to craft ${count} ${itemName}(s). I have ${haveDiamonds}.`);

  if (haveDiamonds < diamondsNeeded) {
    throw new Error(
      `Insufficient diamonds: have ${haveDiamonds}, need ${diamondsNeeded}. Please mine or obtain more diamonds first.`,
    );
  }

  // Ensure a placed crafting table (required for 3x3 recipes)
  const craftingTableBlockDef = mcData.blocksByName["crafting_table"];
  if (!craftingTableBlockDef) {
    throw new Error("This server version does not recognize 'crafting_table' in mcData.");
  }

  let craftingTableBlock = bot.findBlock({
    matching: craftingTableBlockDef.id,
    maxDistance: 32,
  });

  if (!craftingTableBlock) {
    if (bot.chat) bot.chat("No crafting table block found nearby. Will attempt to craft/place one.");

    if (typeof setupCraftingTable === "function") {
      // Delegate to the composable skill which encapsulates finding, crafting, and placing a table.
      try {
        await setupCraftingTable(bot, 32, { allowConsumeInventory: true });
      } catch (err) {
        // Surface a clear error while preserving original stack/message when possible.
        const msg = err && err.message ? err.message : String(err);
        throw new Error(`setupCraftingTable failed: ${msg}`);
      }
    } else {
      // Fallback when setupCraftingTable is not available: minimal inline logic to craft/place a table.
      const craftingTableItemDef = mcData.itemsByName["crafting_table"];
      if (!craftingTableItemDef) {
        throw new Error("This server version does not recognize 'crafting_table' item in mcData.");
      }

      // Ensure we have a crafting_table item (try craftCraftingTable if available, otherwise craftItem primitive)
      let craftingTableItem = bot.inventory.findInventoryItem(craftingTableItemDef.id, null);
      if (!craftingTableItem) {
        if (bot.chat) bot.chat("No crafting_table item in inventory. Attempting to craft one.");
        if (typeof craftCraftingTable === "function") {
          await craftCraftingTable(bot, 1);
        } else {
          await craftItem(bot, "crafting_table", 1);
        }
        craftingTableItem = bot.inventory.findInventoryItem(craftingTableItemDef.id, null);
        if (!craftingTableItem) {
          throw new Error("Failed to craft or obtain a crafting_table item.");
        }
      }

      // Choose a safe placement position
      if (!bot.entity) throw new Error("Bot entity undefined; cannot determine a safe placement position.");
      const foot = bot.entity.position.floored();
      const candidateOffsets = [
        new Vec3(2, 0, 0),
        new Vec3(-2, 0, 0),
        new Vec3(0, 0, 2),
        new Vec3(0, 0, -2),
        new Vec3(2, 0, 2),
        new Vec3(-2, 0, -2),
      ];
      let safeTarget = null;
      for (const off of candidateOffsets) {
        const pos = foot.offset(off.x, off.y, off.z).floored();
        const feetCell = foot;
        const headCell = foot.offset(0, 1, 0).floored();
        if (pos.equals(feetCell) || pos.equals(headCell)) continue;
        const blockAtTarget = bot.blockAt(pos);
        if (!blockAtTarget || blockAtTarget.name === "air") {
          safeTarget = pos;
          break;
        }
      }
      if (!safeTarget) {
        safeTarget = foot.offset(2, 0, 0).floored();
      }

      if (bot.chat) bot.chat(`Placing crafting_table at ${safeTarget}`);
      await placeItem(bot, "crafting_table", safeTarget);
      await bot.waitForTicks(6);
    }

    // re-find the placed block after either path
    craftingTableBlock = bot.findBlock({
      matching: craftingTableBlockDef.id,
      maxDistance: 32,
    });

    if (!craftingTableBlock) {
      throw new Error("No crafting_table found after setup; cannot proceed with 3x3 crafting.");
    }

    if (bot.chat) bot.chat("Crafting table is ready.");
  } else {
    if (bot.chat) bot.chat(`Found existing crafting_table at ${craftingTableBlock.position}.`);
  }

  // Now craft the diamond boots using the provided craftItem primitive.
  if (bot.chat) bot.chat(`Attempting to craft ${count} ${itemName}(s) using craftItem...`);
  await craftItem(bot, itemName, count);
  await bot.waitForTicks(4);

  // Verify result
  const finalCount = getItemCount(itemName);
  if (finalCount >= 1) {
    if (bot.chat) bot.chat(`Crafting complete: now have ${finalCount} ${itemName}(s).`);
  } else {
    if (bot.chat) bot.chat(`Craft attempted but no ${itemName} found in inventory afterwards.`);
  }
  return finalCount;
}

