async function equipDiamondBoots(bot, itemName = "diamond_boots") {
    // This asynchronous routine equips the specified boots (defaulting to diamond_boots) onto the bot's feet: it loads item definitions for the bot's Minecraft version and validates the requested item and bot instance. It waits briefly for inventory synchronization, then checks the current feet slot and returns true immediately if the requested boots are already equipped. If not present in inventory, it attempts to craft the item using any available crafting methods and re-checks the inventory after syncing. If the item is still missing it throws an error; otherwise it equips the item into the feet slot and returns true, or throws an error if equipping fails.
}

nodes.code:
async function equipDiamondBoots(bot, itemName = "diamond_boots") {
  // MUST declare mcData at the very beginning to avoid TDZ errors
  const mcData = require("minecraft-data")(bot.version);

  // Begin main logic
  if (!bot) throw new Error("Bot instance is required");

  const itemDef = mcData.itemsByName[itemName];
  if (!itemDef) {
    throw new Error(`Unknown item name: ${itemName}`);
  }

  try {
    bot.chat(`Attempting to equip ${itemName}...`);
  } catch (e) {
    // ignore chat errors
  }

  // Small wait to ensure inventory is synced
  try { await bot.waitForTicks(2); } catch (_) {}

  // Check current equipment slot for 'feet'
  try {
    const feetSlotIndex = bot.getEquipmentDestSlot
      ? bot.getEquipmentDestSlot("feet")
      : null;
    if (feetSlotIndex !== null && typeof feetSlotIndex === "number") {
      const equipped = bot.inventory.slots[feetSlotIndex];
      if (equipped && equipped.name === itemName) {
        try { bot.chat(`I already have ${itemName} equipped.`); } catch (_) {}
        return true;
      }
    }
  } catch (_) {
    // If getEquipmentDestSlot not available, ignore and proceed
  }

  // Find the item in inventory
  let item = bot.inventory.findInventoryItem(itemDef.id, null);

  // If missing and item is diamond_boots, try to craft using existing skill
  if (!item) {
    if (itemName === "diamond_boots" && typeof craftDiamondBoots === "function") {
      try {
        bot.chat && bot.chat(`No ${itemName} in inventory. Trying to craft one...`);
      } catch (_) {}
      try {
        await craftDiamondBoots(bot, 1, {}); // reuse existing skill
        // wait a bit for inventory sync
        await bot.waitForTicks(4);
      } catch (err) {
        // Crafting failed
        try { bot.chat(`Failed to craft ${itemName}: ${err.message}`); } catch (_) {}
      }
      // re-check inventory
      item = bot.inventory.findInventoryItem(itemDef.id, null);
    } else if (!item) {
      // Generic fallback: try craftItem if available for other item names
      if (typeof craftItem === "function") {
        try {
          bot.chat && bot.chat(`No ${itemName} in inventory. Attempting generic craftItem...`);
        } catch (_) {}
        try {
          await craftItem(bot, itemName, 1);
          await bot.waitForTicks(4);
        } catch (err) {
          try { bot.chat(`Generic crafting failed: ${err.message}`); } catch (_) {}
        }
        item = bot.inventory.findInventoryItem(itemDef.id, null);
      }
    }
  }

  if (!item) {
    throw new Error(`I don't have ${itemName} in inventory and couldn't craft one.`);
  }

  // Equip the item into the feet slot
  try {
    await bot.equip(item, "feet");
    try { bot.chat(`Equipped ${itemName}.`); } catch (_) {}
    return true;
  } catch (err) {
    // If equip failed, give diagnostic chat then throw
    try { bot.chat(`Failed to equip ${itemName}: ${err.message}`); } catch (_) {}
    throw new Error(`Failed to equip ${itemName}: ${err.message}`);
  }
}

nodes.description:
async function craftShield(bot, count = 1, plankVariant = "birch_planks", maxTableDistance = 32) {
    // An async routine that crafts a requested number of shields (default 1) using a specified plank variant (default "birch_planks") while ensuring a crafting table within a maximum distance (default 32); it first validates inputs and that the server recognizes shields, then computes the total planks and iron required. If planks are lacking it crafts additional planks, and if iron is lacking it will attempt to smelt raw iron into ingots when fuel is available, with brief waits for inventory syncs after operations. It ensures or places a crafting table within the allowed range (capped at 32), performs the shield crafting, and returns the final count of shields in inventory. Errors are thrown if required materials remain insufficient or if crafting/table setup fails.
}

nodes.code:
async function craftShield(bot, count = 1, plankVariant = "birch_planks", maxTableDistance = 32) {
  // MUST declare mcData and Vec3 at the very beginning
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Defensive checks
  if (!bot) throw new Error("Bot instance required");
  if (typeof count !== "number" || count <= 0) throw new Error("count must be a positive number");
  if (typeof plankVariant !== "string") throw new Error("plankVariant must be a string");

  // Helpers (defined inside main to satisfy runtime inclusion rules)
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter(it => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  function hasItem(name) {
    return getItemCount(name) > 0;
  }

  // Validate shield exists in mcData
  if (!mcData.itemsByName["shield"]) {
    throw new Error("This server version doesn't recognize 'shield' in mcData");
  }

  bot.chat && bot.chat(`Starting craftShield: need ${count} shield(s)`);

  // Required materials per shield
  const planksPerShield = 6;
  const ironPerShield = 1;

  // Compute totals required
  const totalPlanksNeeded = planksPerShield * count;
  const totalIronNeeded = ironPerShield * count;

  // Ensure planks
  let havePlanks = getItemCount(plankVariant);
  if (havePlanks < totalPlanksNeeded) {
    const missingPlanks = totalPlanksNeeded - havePlanks;
    bot.chat && bot.chat(`Need ${missingPlanks} more ${plankVariant}. Crafting planks...`);
    try {
      // craftItem uses DELTA semantics: craft 'missingPlanks' new planks
      // But since planks are usually crafted as 4 planks per log, calling craftItem with missing may over/under craft.
      await craftItem(bot, plankVariant, missingPlanks);
      // allow inventory sync
      try { await bot.waitForTicks(2); } catch (_) {}
      havePlanks = getItemCount(plankVariant);
      bot.chat && bot.chat(`Now have ${havePlanks} ${plankVariant}.`);
    } catch (err) {
      bot.chat && bot.chat(`Failed to craft planks: ${err.message}`);
      throw err;
    }
    if (havePlanks < totalPlanksNeeded) {
      throw new Error(`Insufficient ${plankVariant} after crafting attempts (${havePlanks}/${totalPlanksNeeded})`);
    }
  } else {
    bot.chat && bot.chat(`Have enough ${plankVariant}: ${havePlanks}/${totalPlanksNeeded}`);
  }

  // Ensure iron_ingot
  let haveIron = getItemCount("iron_ingot");
  if (haveIron < totalIronNeeded) {
    const missingIron = totalIronNeeded - haveIron;
    bot.chat && bot.chat(`Need ${missingIron} more iron_ingot(s). Attempting to smelt raw_iron if available...`);
    // If raw_iron and fuel exist, try smelting
    const rawIronCount = getItemCount("raw_iron");
    const coalCount = getItemCount("coal") + getItemCount("coal_block"); // best-effort
    if (rawIronCount > 0 && coalCount > 0 && typeof smeltItem === "function") {
      // smeltItem signature: smeltItem(bot, itemName, fuelName, count)
      const toSmelt = Math.min(rawIronCount, missingIron);
      try {
        await smeltItem(bot, "raw_iron", "coal", toSmelt);
        try { await bot.waitForTicks(2); } catch (_) {}
        haveIron = getItemCount("iron_ingot");
        bot.chat && bot.chat(`After smelting, have ${haveIron} iron_ingot(s).`);
      } catch (err) {
        bot.chat && bot.chat(`Smelting failed: ${err.message}`);
      }
    }

    // If still missing iron, cannot craft shield unless more iron obtained.
    if (haveIron < totalIronNeeded) {
      throw new Error(`Insufficient iron_ingot(s) (${haveIron}/${totalIronNeeded}). Need to obtain more iron before crafting shield.`);
    }
  } else {
    bot.chat && bot.chat(`Have enough iron_ingot(s): ${haveIron}/${totalIronNeeded}`);
  }

  // Ensure a placed crafting_table block exists within 32 blocks
  let craftTableBlock;
  try {
    const res = await setupCraftingTable(bot, Math.min(maxTableDistance, 32), { allowConsumeInventory: true, plankVariant });
    let pos = null;
    if (res && res.position) pos = res.position;
    else pos = res;
    craftTableBlock = bot.blockAt(pos);
  } catch (err) {
    throw new Error(`Failed to ensure crafting_table: ${err.message}`);
  }

  if (!craftTableBlock) {
    throw new Error("Crafting table placement verification failed: block not found within 32 blocks after placement");
  }
  bot.chat && bot.chat(`Using crafting_table at ${craftTableBlock.position}.`);

  // Finally, craft the shield(s)
  bot.chat && bot.chat(`Crafting ${count} shield(s) now...`);
  try {
    await craftItem(bot, "shield", count);
    try { await bot.waitForTicks(4); } catch (_) {}
  } catch (err) {
    bot.chat && bot.chat(`craftItem failed: ${err.message}`);
    throw err;
  }

  // Return shields count
  const finalShields = getItemCount("shield");
  bot.chat && bot.chat(`Done: have ${finalShields} shield(s) in inventory.`);
  return finalShields;
}

nodes.description:
async function craftBirchPlanks(bot, targetPlanks = 5, plankVariant = "birch_planks", logVariant = "birch_log") {
    // The function crafts a specified number of birch planks (default 5) from birch logs, accepting either plank/log names or an options object that can treat the target as a delta relative to current inventory; it validates inputs and computes the desired total (or target increase) using the vanilla 1 log → 4 planks ratio to plan craft executions. It checks inventory, attempts to obtain missing logs via available recovery or targeted harvesting methods, then performs crafting in bounded retries while waiting for inventory updates and verifying exact inventory deltas to detect unexpected results. If crafting yields fewer planks than expected, consumes more logs than intended, or logs cannot be obtained, it throws an error to avoid resource loss; on success it returns the updated plank count.
}

nodes.code:
async function craftBirchPlanks(bot, targetPlanks = 5, plankVariant = "birch_planks", logVariant = "birch_log") {
  // MUST declare mcData first per environment rules
  const mcData = require("minecraft-data")(bot.version);
  const Vec3 = require("vec3");

  // Parameters compatibility: keep original signature but accept an options object
  // in either plankVariant or logVariant position (backwards-compatible).
  // Supported option: interpretAsDelta (boolean), plankVariant, logVariant
  let plankName = "birch_planks";
  let logName = "birch_log";
  let interpretAsDelta = false;

  // Simplified option detection: prefer an object if provided in either param
  let opts = null;
  if (plankVariant && typeof plankVariant === "object") {
    opts = plankVariant;
  }
  if (!opts && logVariant && typeof logVariant === "object") {
    opts = logVariant;
  }
  if (opts) {
    plankName = opts.plankVariant || plankName;
    logName = opts.logVariant || logName;
    interpretAsDelta = !!opts.interpretAsDelta;
  } else {
    if (typeof plankVariant === "string") plankName = plankVariant || plankName;
    if (typeof logVariant === "string") logName = logVariant || logName;
  }

  // Helper: get total count of an item by exact name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory
      .items()
      .filter((it) => it && it.name === name)
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Basic validation
  if (!mcData.itemsByName[plankName]) {
    throw new Error(`Unknown plank item: ${plankName}`);
  }
  if (!mcData.itemsByName[logName]) {
    throw new Error(`Unknown log item: ${logName}`);
  }
  if (typeof targetPlanks !== "number" || targetPlanks <= 0) {
    throw new Error("targetPlanks must be a positive number");
  }

  // Record initial plank count for delta verification when interpretAsDelta is used
  const initialPlanks = getItemCount(plankName);

  // Determine desired total based on interpretAsDelta flag
  let currentPlanks = initialPlanks;
  const desiredTotal = interpretAsDelta ? currentPlanks + targetPlanks : targetPlanks;

  if (interpretAsDelta) {
    bot.chat(`Goal: craft ${targetPlanks} more ${plankName} (current ${currentPlanks}, target total ${desiredTotal}).`);
  } else {
    bot.chat(`Goal: ensure I have ${desiredTotal} total ${plankName} (currently ${currentPlanks}).`);
  }

  // Quick check
  if (currentPlanks >= desiredTotal) {
    bot.chat(`I already have ${currentPlanks} ${plankName}. Nothing to do.`);
    return currentPlanks;
  }

  // Common vanilla: 1 log -> 4 planks
  const planksPerExec = 4;

  // Retry loop (small number of attempts)
  let attempts = 0;
  const maxAttempts = 3;
  while (attempts < maxAttempts) {
    attempts++;
    currentPlanks = getItemCount(plankName);
    if (currentPlanks >= desiredTotal) {
      bot.chat(`Done: now have ${currentPlanks} ${plankName}.`);
      if (interpretAsDelta) {
        const delta = currentPlanks - initialPlanks;
        if (delta < targetPlanks) {
          throw new Error(`crafted insufficient ${plankName}: delta=${delta} < requested ${targetPlanks}`);
        }
      }
      return currentPlanks;
    }

    const need = desiredTotal - currentPlanks;
    const execsNeeded = Math.ceil(need / planksPerExec);

    // Check logs availability
    let haveLogs = getItemCount(logName);

    // If we have none, attempt recovery via existing ensure skills (prefer ensureWoodLogs),
    // but pass explicit variant options when possible. If helpers are unavailable or do not
    // produce birch_log, attempt targeted mining of birch_log via mineBlock.
    if (haveLogs <= 0) {
      bot.chat(`I don't have any ${logName}. I'll try to obtain ${execsNeeded} ${logName}...`);
      let recoveryError = null;
      try {
        if (typeof ensureWoodLogs === "function") {
          // Prefer variant-aware invocation (options object as 5th parameter)
          try {
            await ensureWoodLogs(bot, execsNeeded, 3, 60, { logVariant: logName });
          } catch (e) {
            // If the helper rejects extra options, retry without options (best-effort)
            try {
              await ensureWoodLogs(bot, execsNeeded, 3, 60);
            } catch (e2) {
              throw e2;
            }
          }
        } else if (typeof ensureLogs === "function") {
          try {
            await ensureLogs(bot, execsNeeded, 3, 60, { logVariant: logName });
          } catch (e) {
            try {
              await ensureLogs(bot, execsNeeded, 3, 60);
            } catch (e2) {
              throw e2;
            }
          }
        } else {
          // No ensure helper available: attempt direct targeted mining of the exact birch_log
          await mineBlock(bot, logName, execsNeeded);
        }
      } catch (e) {
        recoveryError = e;
      }

      // Re-evaluate logs after recovery attempt
      haveLogs = getItemCount(logName);

      // If still zero, check if other log types are present (helper returned generic wood only)
      if (haveLogs <= 0) {
        const otherLogs = bot.inventory
          .items()
          .filter((it) => it && it.name && it.name.endsWith("_log") && it.name !== logName)
          .reduce((sum, it) => sum + it.count, 0);
        if (otherLogs > 0) {
          bot.chat(
            `Helper obtained other log types (${otherLogs}) but no ${logName}. Attempting targeted harvest of ${logName}.`,
          );
          // Try targeted mining for birch_log specifically
          try {
            const mined = await mineBlock(bot, logName, execsNeeded);
            haveLogs = getItemCount(logName);
            if (haveLogs <= 0 && mined === 0) {
              throw new Error(`Helper returned other wood but no ${logName} found nearby to mine`);
            }
          } catch (e) {
            const reason = recoveryError ? recoveryError.message + " | " + e.message : e.message;
            throw new Error(
              `Insufficient ${logName} to craft ${plankName}: attempted to obtain ${execsNeeded} but have ${haveLogs}. Reason: ${reason}`,
            );
          }
        } else {
          const reason = recoveryError ? recoveryError.message : "no logs obtained";
          throw new Error(
            `Insufficient ${logName} to craft ${plankName}: attempted to obtain ${execsNeeded} but have ${haveLogs}. Reason: ${reason}`,
          );
        }
      }
    }

    if (haveLogs < execsNeeded) {
      bot.chat(
        `I have ${haveLogs} ${logName} but need ${execsNeeded} crafting executions to reach ${desiredTotal} ${plankName}. ` +
          `I'll attempt to craft ${haveLogs} time(s) to produce ${haveLogs * planksPerExec} planks and re-evaluate.`,
      );
    } else {
      bot.chat(`Crafting ${execsNeeded} time(s) ${plankName} from ${logName}...`);
    }

    // Determine how many executions we will attempt this pass (don't exceed available logs)
    const execsThisPass = Math.min(execsNeeded, haveLogs);

    // Record inventory before crafting for verification
    const logsBefore = getItemCount(logName);
    const planksBefore = getItemCount(plankName);

    // Perform craft and wait for inventory sync. Do NOT swallow errors - log then rethrow.
    try {
      await craftItem(bot, plankName, execsThisPass);
      if (typeof waitForInventorySync === "function") {
        await waitForInventorySync(bot, 4);
      } else {
        await bot.waitForTicks(4);
      }
    } catch (err) {
      bot.chat(`craftItem or inventory sync failed: ${err.message}`);
      throw err;
    }

    // Verify actual inventory delta vs expected
    const logsAfter = getItemCount(logName);
    const planksAfter = getItemCount(plankName);
    const consumedLogs = logsBefore - logsAfter;
    const producedPlanks = planksAfter - planksBefore;
    const expectedProduced = execsThisPass * planksPerExec;
    const expectedConsumed = execsThisPass;

    if (producedPlanks < expectedProduced || consumedLogs > expectedConsumed) {
      throw new Error(
        `Unexpected craft result: expected +${expectedProduced} ${plankName} consuming ${expectedConsumed} ${logName}, ` +
          `got +${producedPlanks} and consumed ${consumedLogs}. Aborting to avoid resource loss.`,
      );
    }

    // Re-check after successful crafting and verification
    currentPlanks = getItemCount(plankName);
    bot.chat(`After attempt ${attempts}: I have ${currentPlanks} ${plankName}.`);

    // If interpretAsDelta mode, check delta produced so far and return if satisfied
    if (interpretAsDelta) {
      const delta = currentPlanks - initialPlanks;
      if (delta >= targetPlanks) {
        bot.chat(`Success: produced ${delta} ${plankName} (requested ${targetPlanks}).`);
        return currentPlanks;
      }
    } else {
      if (currentPlanks >= desiredTotal) {
        bot.chat(`Success: obtained ${currentPlanks} ${plankName}.`);
        return currentPlanks;
      }
    }

    // If still short, loop again (may craft remaining logs next pass)
  }

  // Final check and error if we still couldn't reach target
  currentPlanks = getItemCount(plankName);
  if (interpretAsDelta) {
    const delta = currentPlanks - initialPlanks;
    if (delta >= targetPlanks) {
      bot.chat(`Success after retries: produced ${delta} ${plankName}.`);
      return currentPlanks;
    }
    bot.chat(`Failed to produce ${targetPlanks} ${plankName} after ${maxAttempts} attempts. Produced ${delta} only.`);
    throw new Error(`Could not craft enough ${plankName}: produced ${delta}, requested ${targetPlanks}`);
  } else {
    if (currentPlanks >= desiredTotal) {
      bot.chat(`Success after retries: have ${currentPlanks} ${plankName}.`);
      return currentPlanks;
    } else {
      bot.chat(
        `Failed to obtain ${desiredTotal} ${plankName} after ${maxAttempts} attempts. Currently have ${currentPlanks}.`,
      );
      throw new Error(`Could not craft enough ${plankName} (have ${currentPlanks}, need ${desiredTotal})`);
    }
  }
}

async function findChestsNearby(bot, radius = 6) {
  // Self-contained helper to locate chest block positions around the bot within a radius.
  // This function does not rely on any external helpers and only uses data parameters.
  if (!bot) return [];
  if (!bot.entity) return [];
  // Ensure radius is a reasonable number
  if (typeof radius !== 'number' || !isFinite(radius) || radius < 0) radius = 6;

  const center = bot.entity.position.floored();
  const found = [];
  // Limit vertical search to avoid excessive ranges (match prior behavior)
  const yLimit = Math.min(6, Math.floor(radius));
  for (let dx = -radius; dx <= radius; dx++) {
    for (let dy = -yLimit; dy <= yLimit; dy++) {
      for (let dz = -radius; dz <= radius; dz++) {
        const pos = center.offset(dx, dy, dz);
        const b = bot.blockAt(pos);
        if (b && b.name === "chest") {
          found.push(b.position);
        }
      }
    }
  }
  return found;
}

