async function craftBucket(bot, count = 1) {
  // MUST declare mcData and Vec3 first
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: total count of an item name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory.items()
      .filter(it => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Helper: try to find a placed crafting table within 32 blocks
  function findPlacedCraftingTable() {
    const tableDef = mcData.blocksByName["crafting_table"];
    if (!tableDef) return null;
    return bot.findBlock({ matching: tableDef.id, maxDistance: 32 });
  }

  // Helper: pick a placement position (uses findNearbyOpenArea if available)
  async function choosePlacePosition() {
    // prefer using provided helper if available
    try {
      if (typeof findNearbyOpenArea === "function") {
        const pos = await findNearbyOpenArea(bot, bot.entity ? bot.entity.position.floored() : null, 6);
        if (pos) return pos;
      }
    } catch (e) {
      // ignore and fallback
    }
    if (!bot.entity) throw new Error("Bot entity undefined; cannot determine placement position.");
    return bot.entity.position.floored().offset(1, 0, 0);
  }

  // 0) Validate parameters and mcData items
  if (!bot) throw new Error("Bot instance required");
  if (typeof count !== "number" || count <= 0) throw new Error("count must be a positive number");

  const bucketItem = mcData.itemsByName["bucket"];
  const ironItem = mcData.itemsByName["iron_ingot"];
  if (!bucketItem) throw new Error("This server version does not recognize 'bucket' in mcData");
  if (!ironItem) throw new Error("This server version does not recognize 'iron_ingot' in mcData");

  bot.chat && bot.chat(`Starting craftBucket: need ${count} bucket(s)`);

  // 1) Ensure required iron ingots (3 per bucket)
  const requiredIngots = 3 * count;
  let haveIngots = getItemCount("iron_ingot");
  if (haveIngots < requiredIngots) {
    const targetTotal = requiredIngots;
    bot.chat && bot.chat(`I need ${requiredIngots} iron_ingot(s), have ${haveIngots}. Attempting to smelt more...`);
    if (typeof smeltIngots === "function") {
      try {
        // smeltIngots ensures you end up with targetCount ingots total
        await smeltIngots(bot, "iron_ingot", targetTotal, 60, 6);
      } catch (err) {
        bot.chat && bot.chat(`Smelting iron failed: ${err.message}`);
        throw err;
      }
    } else {
      throw new Error("No smeltIngots helper available to produce required iron ingots");
    }
    // wait a tick for inventory sync
    try { await bot.waitForTicks(2); } catch (_) {}
    haveIngots = getItemCount("iron_ingot");
    if (haveIngots < requiredIngots) {
      throw new Error(`After smelting, still only have ${haveIngots}/${requiredIngots} iron_ingot(s)`);
    }
    bot.chat && bot.chat(`Now have ${haveIngots} iron_ingot(s).`);
  } else {
    bot.chat && bot.chat(`Have sufficient iron_ingot(s): ${haveIngots}/${requiredIngots}`);
  }

  // 2) Ensure a placed crafting table within 32 blocks (needed for bucket 3x3 recipe)
  // Delegate placement/crafting/selection to the specialized helper setupCraftingTable
  let tableBlock;
  try {
    const setupResult = await setupCraftingTable(bot, 32, { allowConsumeInventory: true });
    // setupResult is expected to be an object with { position: Vec3, placed: boolean }
    let pos = null;
    if (!setupResult) {
      pos = null;
    } else if (setupResult.position) {
      pos = setupResult.position;
    } else if (typeof setupResult.x === "number" && typeof setupResult.y === "number" && typeof setupResult.z === "number") {
      pos = setupResult;
    } else {
      // maybe it's a Vec3-like returned directly
      pos = setupResult;
    }

    if (pos) {
      tableBlock = bot.blockAt(pos);
    } else {
      // fallback: attempt to find a placed crafting table nearby as the original logic did
      tableBlock = findPlacedCraftingTable();
    }
  } catch (err) {
    bot.chat && bot.chat(`Failed to ensure crafting_table: ${err.message}`);
    throw err;
  }

  if (!tableBlock) {
    throw new Error("Could not locate crafting_table after setupCraftingTable");
  }
  bot.chat && bot.chat(`Using crafting_table at ${tableBlock.position}.`);

  // 3) Craft the bucket(s) using craftItem
  bot.chat && bot.chat(`Crafting ${count} bucket(s) now...`);
  if (typeof craftItem !== "function") {
    throw new Error("craftItem helper is not available to craft the bucket");
  }
  try {
    await craftItem(bot, "bucket", count);
    try { await bot.waitForTicks(2); } catch (_) {}
  } catch (err) {
    bot.chat && bot.chat(`Failed to craft bucket: ${err.message}`);
    throw err;
  }

  // 4) Final inventory count and report
  const finalBuckets = getItemCount("bucket");
  bot.chat && bot.chat(`Done: have ${finalBuckets} bucket(s) in inventory.`);
  return finalBuckets;
}

