async function craftGoldenApple(bot, count = 1, maxTableDistance = 32, placeRadius = 6, exploreTime = 60) {
  // IMPORTANT: declare mcData and Vec3 at the VERY BEGINNING to avoid TDZ errors
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: total count of an item name in inventory
  function getItemCount(name) {
    if (!name) return 0;
    return bot.inventory.items()
      .filter(it => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Helper: ensure we have required number of gold_ingot in inventory (target total).
  // Uses smeltIngots(bot, "gold_ingot", targetTotal, exploreTime) if necessary.
  async function ensureGoldIngots(targetTotal) {
    const have = getItemCount("gold_ingot");
    if (have >= targetTotal) {
      bot.chat(`Have ${have} gold_ingot(s) (need ${targetTotal}).`);
      return;
    }
    bot.chat(`Need ${targetTotal} gold_ingot(s), currently have ${have}. Attempting to obtain via smelting/mining...`);
    if (typeof smeltIngots === "function") {
      try {
        // smeltIngots uses targetCount semantics (ensure total)
        await smeltIngots(bot, "gold_ingot", targetTotal, exploreTime, placeRadius);
        await bot.waitForTicks(4);
      } catch (err) {
        throw new Error(`Failed to obtain gold_ingot(s): ${err.message}`);
      }
    } else if (typeof doSmeltIngots === "function") {
      try {
        await doSmeltIngots(bot, targetTotal, exploreTime, placeRadius);
        await bot.waitForTicks(4);
      } catch (err) {
        throw new Error(`Failed to obtain gold_ingot(s) via doSmeltIngots: ${err.message}`);
      }
    } else {
      throw new Error("No smelting helper available to obtain gold_ingot(s).");
    }
    const now = getItemCount("gold_ingot");
    if (now < targetTotal) throw new Error(`After smelting attempts, have ${now}/${targetTotal} gold_ingot(s).`);
    bot.chat(`Obtained required gold_ingot(s): ${now}/${targetTotal}.`);
  }

  // Helper: small best-effort to get an apple if none present.
  // Tries mining 1 oak_leaves once. Apple drops are rare; this may fail.
  async function tryGetAppleOnce() {
    const have = getItemCount("apple");
    if (have > 0) return;
    bot.chat("I don't have an apple. Attempting to break some oak_leaves nearby to get an apple (chance-based).");
    // Check for nearby oak_leaves within 32 blocks
    const oakLeavesDef = mcData.blocksByName["oak_leaves"];
    if (!oakLeavesDef) {
      bot.chat("This server version does not recognize 'oak_leaves'. Cannot attempt to get apple automatically.");
      return;
    }
    const leavesBlock = bot.findBlock({ matching: oakLeavesDef.id, maxDistance: 32 });
    if (!leavesBlock) {
      bot.chat("No oak_leaves found within 32 blocks to break for apples.");
      return;
    }
    try {
      // Use mineBlock helper to attempt to mine leaves (may drop apple)
      const gained = await mineBlock(bot, "oak_leaves", 1);
      await bot.waitForTicks(2);
      const now = getItemCount("apple");
      if (now > 0) {
        bot.chat(`Got an apple! Now have ${now}.`);
      } else {
        bot.chat("Did not get an apple from that leaf break (apple drops are rare).");
      }
    } catch (err) {
      bot.chat(`Failed to mine oak_leaves: ${err.message}`);
    }
  }

  // ----------------- main logic -----------------
  if (!bot) throw new Error("Bot instance required");

  if (!mcData.itemsByName["gold_ingot"]) throw new Error("Server mcData does not contain 'gold_ingot'.");
  if (!mcData.itemsByName["apple"]) throw new Error("Server mcData does not contain 'apple'.");

  if (typeof count !== "number" || count <= 0) throw new Error("count must be a positive number");

  const requiredIngots = 8 * count;
  const requiredApples = 1 * count;

  bot.chat(`CraftGoldenApple: trying to craft ${count} golden_apple(s).`);

  // Ensure apple(s)
  let haveApples = getItemCount("apple");
  if (haveApples < requiredApples) {
    await tryGetAppleOnce();
    haveApples = getItemCount("apple");
    if (haveApples < requiredApples) {
      throw new Error(`Not enough apples. Have ${haveApples}, need ${requiredApples}. Consider collecting more apples from oak leaves.`);
    }
  }

  // Ensure gold_ingot(s)
  await ensureGoldIngots(requiredIngots);

  // Ensure a crafting table block is placed (delegated to setupCraftingTable)
  try {
    const res = await setupCraftingTable(bot, maxTableDistance, { placeRadius });
    // res.position is where the table is/was placed
  } catch (err) {
    throw new Error(`Failed to ensure crafting_table: ${err.message}`);
  }

  // Finally craft using craftItem (this handles table interaction/navigation)
  bot.chat(`Crafting ${count} golden_apple(s) now...`);
  try {
    await craftItem(bot, "golden_apple", count);
    await bot.waitForTicks(4);
  } catch (err) {
    throw new Error(`craftItem failed for golden_apple: ${err.message}`);
  }

  // Report final count
  const final = getItemCount("golden_apple");
  bot.chat(`Done: now have ${final} golden_apple(s) in inventory.`);
  return final;
}

