async function ensureTorches(bot, targetTotal = 16, exploreTime = 60) {
    // Ensures the bot holds at least a target number of torches (default 16) by checking current torches, computing how many torch recipes are needed (4 torches per recipe), and making sure there is enough coal/charcoal and sticks; if sticks are missing it will craft them, producing planks from logs or obtaining logs when necessary, then craft the required torch recipes and retry once after rechecking resources if crafting fails, finally returning the resulting torch count or throwing an error if the target was not reached.
}

nodes.code:
async function ensureTorches(bot, targetTotal = 16, exploreTime = 60) {
  // CRITICAL: mcData at very beginning
  const mcData = require("minecraft-data")(bot.version);

  // Helper: total count of an item by exact name in inventory
  function getItemCount(name) {
    return bot.inventory.items()
      .filter(it => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Helper: total coal + charcoal
  function getCoalTotal() {
    return getItemCount("coal") + getItemCount("charcoal");
  }

  // Helper: find any plank variant name present in inventory (returns name or null)
  function findAnyPlankName() {
    const items = bot.inventory.items();
    for (const it of items) {
      if (!it || !it.name) continue;
      if (it.name.endsWith("_planks")) return it.name;
    }
    return null;
  }

  // Helper: find any log name present in inventory (returns name or null)
  function findAnyLogName() {
    const items = bot.inventory.items();
    for (const it of items) {
      if (!it || !it.name) continue;
      if (it.name.endsWith("_log")) return it.name;
    }
    return null;
  }

  // Start
  bot.chat && bot.chat(`Ensuring ${targetTotal} torches...`);

  // Validate mcData has torch
  if (!mcData.itemsByName["torch"]) {
    throw new Error("This server version does not have item 'torch' in mcData");
  }

  // 1) Check current torches
  let haveTorches = getItemCount("torch");
  if (haveTorches >= targetTotal) {
    bot.chat && bot.chat(`I already have ${haveTorches} torches (>= ${targetTotal}).`);
    return haveTorches;
  }

  // 2) Compute needed recipes (1 coal + 1 stick -> yields 4 torches per recipe)
  const torchesPerRecipe = 4;
  const needTorches = targetTotal - haveTorches;
  let recipesNeeded = Math.ceil(needTorches / torchesPerRecipe);
  bot.chat && bot.chat(`Need ${needTorches} more torches -> ${recipesNeeded} recipe execution(s).`);

  // 3) Ensure enough coal/charcoal (ensureCoalOrCharcoal expects target total)
  const currentCoal = getCoalTotal();
  if (currentCoal < recipesNeeded) {
    bot.chat && bot.chat(`I have ${currentCoal} coal/charcoal, need ${recipesNeeded}. Trying to obtain more...`);
    await ensureCoalOrCharcoal(bot, recipesNeeded, exploreTime);
    // Wait a tick to sync inventories
    await bot.waitForTicks(2);
  }

  // 4) Ensure enough sticks. Each recipe consumes 1 stick.
  let currentSticks = getItemCount("stick");
  if (currentSticks < recipesNeeded) {
    const sticksNeeded = recipesNeeded - currentSticks;
    // Each stick-crafting recipe yields 4 sticks (from 2 planks). stickRecipes = number of recipe executions needed
    const stickRecipes = Math.ceil(sticksNeeded / 4);
    bot.chat && bot.chat(`I have ${currentSticks} sticks, need ${recipesNeeded}. Will craft sticks (${stickRecipes} recipe(s)).`);

    // Attempt to craft sticks; if it fails due to missing planks, try to produce planks from logs or gather logs
    try {
      await craftItem(bot, "stick", stickRecipes);
      await bot.waitForTicks(2);
    } catch (err) {
      bot.chat && bot.chat(`Crafting sticks failed: ${err.message}. Attempting to craft planks/log fallback...`);
      // Determine required planks
      const planksNeeded = stickRecipes * 2; // each stick recipe consumes 2 planks
      // Prefer crafting a plank variant already in inventory; otherwise, derive from a log in inventory
      let plankName = findAnyPlankName();
      if (!plankName) {
        // Try to craft planks from a log type we have
        const logName = findAnyLogName();
        if (logName) {
          // e.g., oak_log -> oak_planks
          plankName = logName.replace(/_log$/, "_planks");
          // compute how many plank recipe executions (one log -> 4 planks) needed
          const currentPlanks = getItemCount(plankName);
          if (currentPlanks < planksNeeded) {
            const morePlanksNeeded = planksNeeded - currentPlanks;
            const logRecipes = Math.ceil(morePlanksNeeded / 4); // each log -> 4 planks
            bot.chat && bot.chat(`Crafting ${logRecipes} ${plankName} recipes from logs to obtain planks...`);
            try {
              await craftItem(bot, plankName, logRecipes);
              await bot.waitForTicks(2);
            } catch (craftPlankErr) {
              bot.chat && bot.chat(`Failed to craft ${plankName}: ${craftPlankErr.message}`);
            }
          }
        } else {
          // No planks and no logs in inventory, try to gather logs via ensureResource
          bot.chat && bot.chat("No planks or logs in inventory. Trying to obtain logs...");
          // Determine how many logs we might need: each log -> 4 planks -> 2 planks per stick recipe -> logsPerStickRecipes = ceil(planksNeeded/4)
          const logsNeeded = Math.max(1, Math.ceil(planksNeeded / 4));
          try {
            // ensureResource expects targetTotal for logs; compute current logs and request current + logsNeeded
            const currentLogs = bot.inventory.items().filter(it => it && it.name && it.name.endsWith("_log")).reduce((s, it) => s + it.count, 0);
            const targetLogsTotal = currentLogs + logsNeeded;
            await ensureResource(bot, "logs", targetLogsTotal, 3, exploreTime);
            await bot.waitForTicks(2);
            // After ensureResource, pick a plank variant (we'll craft from logs)
            const newLogName = findAnyLogName();
            if (newLogName) plankName = newLogName.replace(/_log$/, "_planks");
            // craft required planks from logs
            const currentPlanks = plankName ? getItemCount(plankName) : 0;
            if (plankName && currentPlanks < planksNeeded) {
              const morePlanksNeeded = planksNeeded - currentPlanks;
              const logRecipes = Math.ceil(morePlanksNeeded / 4);
              try {
                await craftItem(bot, plankName, logRecipes);
                await bot.waitForTicks(2);
              } catch (craftPlankErr2) {
                bot.chat && bot.chat(`Failed to craft ${plankName} from logs: ${craftPlankErr2.message}`);
              }
            }
          } catch (ensureLogErr) {
            bot.chat && bot.chat(`Failed to obtain logs: ${ensureLogErr.message}`);
          }
        } // end no plankName
      } else {
        // We have some planks but maybe not enough; ensure enough planks to craft sticks
        const currentPlanks = getItemCount(plankName);
        if (currentPlanks < planksNeeded) {
          const morePlanksNeeded = planksNeeded - currentPlanks;
          const logRecipes = Math.ceil(morePlanksNeeded / 4);
          // Try to craft planks from any log available
          const logName = findAnyLogName();
          if (logName) {
            const derivedPlankName = logName.replace(/_log$/, "_planks");
            try {
              await craftItem(bot, derivedPlankName, logRecipes);
              await bot.waitForTicks(2);
              plankName = derivedPlankName;
            } catch (err2) {
              bot.chat && bot.chat(`Failed to craft ${derivedPlankName}: ${err2.message}`);
            }
          } else {
            // Try ensureResource to get logs
            try {
              const currentLogs = bot.inventory.items().filter(it => it && it.name && it.name.endsWith("_log")).reduce((s, it) => s + it.count, 0);
              const targetLogsTotal = currentLogs + Math.max(1, logRecipes);
              await ensureResource(bot, "logs", targetLogsTotal, 3, exploreTime);
              await bot.waitForTicks(2);
              const newLogName = findAnyLogName();
              if (newLogName) {
                const derivedPlankName = newLogName.replace(/_log$/, "_planks");
                await craftItem(bot, derivedPlankName, logRecipes);
                await bot.waitForTicks(2);
                plankName = derivedPlankName;
              }
            } catch (ensureErr) {
              bot.chat && bot.chat(`Failed to obtain logs for planks: ${ensureErr.message}`);
            }
          }
        }
      } // end plank/log fallback

      // After trying to produce planks, retry crafting sticks once
      try {
        await craftItem(bot, "stick", stickRecipes);
        await bot.waitForTicks(2);
      } catch (finalStickErr) {
        // If still fails, bubble up a descriptive error
        throw new Error(`Unable to craft required sticks: ${finalStickErr.message}`);
      }
    } // end stick craft fallback

    // update current sticks
    currentSticks = getItemCount("stick");
    bot.chat && bot.chat(`Now have ${currentSticks} sticks.`);
  } // end sticks ensure

  // 5) Finally craft torches: run recipesNeeded times (each run yields 4 torches)
  bot.chat && bot.chat(`Crafting ${recipesNeeded} torch recipe(s) to obtain ~${recipesNeeded * torchesPerRecipe} torches...`);
  try {
    await craftItem(bot, "torch", recipesNeeded);
    await bot.waitForTicks(2);
  } catch (craftTorchErr) {
    // If craftItem fails, try to diagnose if missing coal or sticks
    bot.chat && bot.chat(`Crafting torches failed: ${craftTorchErr.message}`);
    // Attempt to ensure coal again and retry once
    const coalNow = getCoalTotal();
    const sticksNow = getItemCount("stick");
    if (coalNow < recipesNeeded) {
      bot.chat && bot.chat(`Coal still short (${coalNow} < ${recipesNeeded}), trying to get coal...`);
      await ensureCoalOrCharcoal(bot, recipesNeeded, exploreTime);
      await bot.waitForTicks(2);
    }
    if (sticksNow < recipesNeeded) {
      bot.chat && bot.chat(`Sticks still short (${sticksNow} < ${recipesNeeded}), attempting to craft sticks...`);
      const sticksNeeded = recipesNeeded - sticksNow;
      const stickRecipes = Math.ceil(sticksNeeded / 4);
      await craftItem(bot, "stick", stickRecipes);
      await bot.waitForTicks(2);
    }
    // Retry craft torches once more
    try {
      await craftItem(bot, "torch", recipesNeeded);
      await bot.waitForTicks(2);
    } catch (retryErr) {
      throw new Error(`Failed to craft torches after retry: ${retryErr.message}`);
    }
  }

  // 6) Final report
  haveTorches = getItemCount("torch");
  if (haveTorches >= targetTotal) {
    bot.chat && bot.chat(`Success: I now have ${haveTorches} torches (target ${targetTotal}).`);
    return haveTorches;
  } else {
    const deficit = targetTotal - haveTorches;
    throw new Error(`Finished crafting but only have ${haveTorches} torches (need ${deficit} more).`);
  }
}

