async function ensuiamondHorseArmor(bot, targetTotal = 1, maxChestSearchDistance = 32, exploreTime = 60) {
    // This async routine ensures the bot acquires a specified number of diamond horse armors by verifying the item exists, checking current inventory, scanning nearby chests within a configurable radius and moving to/opening them to withdraw needed pieces, and if still short it will explore for up to a configurable time to locate additional chests and attempt withdrawals again, finally returning the total count (or throwing if the item is unrecognized).
}

