async function ensuiamondHorseArmor(bot, targetTotal = 1, maxChestSearchDistance = 32, exploreTime = 60) {
  // Obtain shared helpers (mcData, Vec3, getItemCount)
  const { mcData, Vec3, getItemCount } = await provideInventoryHelpers(bot);

  // Helper: move near a position using pathfinder GoalNear and simple polling
  async function moveNearPosition(pos, range = 2, timeoutMs = 30000) {
    if (!bot.pathfinder || typeof bot.pathfinder.setGoal !== "function") {
      // If no pathfinder, just try to rely on being already close
      return;
    }
    // GoalNear is expected to be available in the environment
    const goal = new GoalNear(pos.x, pos.y, pos.z, range);
    bot.pathfinder.setGoal(goal);
    const start = Date.now();
    return new Promise((resolve, reject) => {
      const checkInterval = 250;
      const id = setInterval(() => {
        if (!bot.entity) {
          clearInterval(id);
          bot.pathfinder.setGoal(null);
          return reject(new Error("Bot entity undefined (died or disconnected)"));
        }
        const dist = bot.entity.position.distanceTo(new Vec3(pos.x + 0.5, pos.y + 0.5, pos.z + 0.5));
        if (dist <= range + 0.5) {
          clearInterval(id);
          bot.pathfinder.setGoal(null);
          return resolve();
        }
        if (Date.now() - start > timeoutMs) {
          clearInterval(id);
          bot.pathfinder.setGoal(null);
          return reject(new Error(`Timed out moving near (${pos.x},${pos.y},${pos.z})`));
        }
      }, checkInterval);
    });
  }

  // Helper: attempt to withdraw desired item from a chest block
  async function tryWithdrawFromChestAt(blockPos, itemName, neededCount) {
    // Defensive blockAt check (chunk may be unloaded)
    const block = bot.blockAt(blockPos);
    if (!block) {
      bot.chat(`Chest at ${blockPos} not loaded`);
      return 0;
    }
    if (block.name !== "chest" && block.name !== "trapped_chest") {
      // Not a chest
      return 0;
    }
    try {
      bot.chat(`Moving to chest at ${blockPos}`);
      await moveNearPosition(blockPos, 2, 20000);
    } catch (err) {
      bot.chat(`Failed to reach chest at ${blockPos}: ${err.message}`);
      return 0;
    }
    let chest;
    try {
      chest = await bot.openContainer(block);
    } catch (err) {
      bot.chat(`Failed to open chest at ${blockPos}: ${err.message}`);
      return 0;
    }
    try {
      const itemDef = mcData.itemsByName[itemName];
      if (!itemDef) {
        bot.chat(`Item ${itemName} unknown to mcData`);
        try {
          await chest.close();
        } catch (_) {}
        return 0;
      }
      const contItem = chest.findContainerItem(itemDef.id);
      if (!contItem) {
        // Nothing to withdraw here
        await chest.close();
        return 0;
      }
      const take = Math.min(neededCount, contItem.count);
      try {
        await chest.withdraw(contItem.type, null, take);
      } catch (withdrawErr) {
        bot.chat(`Withdraw error: ${withdrawErr.message}`);
        // attempt to take whatever possible (best-effort)
        try {
          await chest.withdraw(contItem.type, null, take);
        } catch (_) {}
      }
      await chest.close();
      bot.chat(`Took up to ${take} ${itemName} from chest at ${blockPos}`);
      // Wait a tick for inventory sync
      (await bot.waitForTicks) ? bot.waitForTicks(2) : new Promise(r => setTimeout(r, 100));
      return take;
    } catch (err) {
      try {
        await chest.close();
      } catch (_) {}
      bot.chat(`Error handling chest at ${blockPos}: ${err.message}`);
      return 0;
    }
  }

  // Begin main logic
  const itemName = "diamond_horse_armor";
  if (!mcData.itemsByName[itemName]) {
    throw new Error(`${itemName} is not recognized by mcData for this server version.`);
  }

  // 1) Quick inventory check
  let have = getItemCount(itemName);
  if (have >= targetTotal) {
    bot.chat(`I already have ${have} ${itemName}(s).`);
    return have;
  }
  bot.chat(`Need ${targetTotal} ${itemName}(s). I have ${have}. Searching nearby chests...`);

  // 2) Find chest blocks within radius
  async function scanNearbyChestsAndWithdraw() {
    const chestBlockDef = mcData.blocksByName["chest"];
    if (!chestBlockDef) throw new Error("mcData missing 'chest' block definition");
    const positions = bot.findBlocks ? bot.findBlocks({
      matching: chestBlockDef.id,
      maxDistance: maxChestSearchDistance,
      count: 256
    }) : [];
    // If findBlocks returned Vec3 arrays (positions), iterate them
    for (const pos of positions) {
      // pos may be a Vec3 or plain object
      const posVec = pos instanceof Vec3 ? pos : new Vec3(pos.x, pos.y, pos.z);
      // try withdraw
      const needed = targetTotal - getItemCount(itemName);
      if (needed <= 0) return true;
      const taken = await tryWithdrawFromChestAt(posVec, itemName, needed);
      if (taken > 0) {
        have = getItemCount(itemName);
        if (have >= targetTotal) {
          bot.chat(`Acquired ${have} ${itemName}(s).`);
          return true;
        }
      }
    }
    return false;
  }

  // First attempt without exploring
  try {
    const ok = await scanNearbyChestsAndWithdraw();
    if (ok) return getItemCount(itemName);
  } catch (e) {
    bot.chat(`Error scanning chests: ${e.message}`);
  }

  // 3) If not found, explore for chests (best-effort)
  bot.chat(`No diamond horse armor found in nearby chests. Exploring for up to ${exploreTime}s...`);
  try {
    // exploreUntil is expected to be available in the environment per guidelines.
    if (typeof exploreUntil === "function") {
      // choose a few random directions attempts but keep single exploreUntil call with callback
      const dir = new Vec3(0, 0, 1); // vertical component 0 so we stay roughly level in caves
      const found = await exploreUntil(bot, dir, exploreTime, () => {
        // Callback should return truthy when a useful chest exists nearby
        const chestBlockDef = mcData.blocksByName["chest"];
        if (!chestBlockDef) return false;
        const chest = bot.findBlock({
          matching: chestBlockDef.id,
          maxDistance: maxChestSearchDistance
        });
        if (!chest) return false;
        // We return the chest block if found (exploreUntil will stop)
        return chest;
      });
      if (found) {
        bot.chat("Exploration found a chest, scanning nearby chests...");
        const ok2 = await scanNearbyChestsAndWithdraw();
        if (ok2) return getItemCount(itemName);
      } else {
        bot.chat("Exploration did not find any chest within the time limit.");
      }
    } else {
      bot.chat("exploreUntil() not available in this environment; cannot explore automatically.");
    }
  } catch (err) {
    bot.chat(`Exploration error: ${err.message}`);
  }

  // 4) If still not found, report failure
  have = getItemCount(itemName);
  if (have >= targetTotal) {
    bot.chat(`Acquired ${have} ${itemName}(s).`);
    return have;
  } else {
    bot.chat(`Failed to obtain ${targetTotal} ${itemName}(s). I have ${have}.`);
    return have;
  }
}

async function provideInventoryHelpers(bot) {
  // Self-contained helper provider for inventory + mcData utilities.
  // CRITICAL: require mcData and Vec3 here so callers can use them safely after awaiting this function.
  if (!bot) throw new Error("Bot instance required");
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: total item count of a given item name in inventory
  function getItemCount(name) {
    return bot.inventory
      .items()
      .filter(it => it && it.name === name)
      .reduce((s, it) => s + it.count, 0);
  }

  // Return an object of utilities so callers can destructure what they need
  return { mcData, Vec3, getItemCount };
}

