async function ensureLapis(bot, targetTotal = 8, exploreTime = 60, maxAttempts = 3) {
  // CRITICAL: declare mcData and Vec3 at the very beginning
  const mcData = require('minecraft-data')(bot.version);
  const { Vec3 } = require('vec3');

  // Helper: get total count of an item in inventory by item name
  function getItemCountByName(itemName) {
    return bot.inventory.items()
      .filter(it => it && it.name === itemName)
      .reduce((sum, it) => sum + it.count, 0);
  }

  // Helper: find a lapis ore block within 32 blocks. Returns Block or null.
  function findNearbyLapisOre() {
    // Determine which block names exist in this mcData/version
    const names = [];
    if (mcData.blocksByName['lapis_ore']) names.push('lapis_ore');
    if (mcData.blocksByName['deepslate_lapis_ore']) names.push('deepslate_lapis_ore');

    if (names.length === 0) return null;

    // Use bot.findBlock with matching function to include any variant
    return bot.findBlock({
      matching: (b) => {
        if (!b) return false;
        return names.includes(b.name);
      },
      maxDistance: 32,
    });
  }

  // Helper: move near a block (uses gotoWithTimeout)
  async function moveNearBlock(block) {
    if (!block || !block.position) throw new Error('Invalid block to move near');
    const pos = block.position;
    await gotoWithTimeout(bot, new GoalNear(pos.x, pos.y, pos.z, 2), 30000, `lapis ore at ${pos.x},${pos.y},${pos.z}`);
  }

  // Start main logic
  if (!bot) throw new Error('Bot instance required');
  if (!bot.entity) {
    throw new Error('Bot entity undefined (dead/disconnected).');
  }
  if (typeof targetTotal !== 'number' || targetTotal <= 0) {
    throw new Error('targetTotal must be a positive number');
  }

  bot.chat(`Ensuring I have ${targetTotal} lapis_lazuli...`);
  let current = getItemCountByName('lapis_lazuli');
  if (current >= targetTotal) {
    bot.chat(`Already have ${current}/${targetTotal} lapis_lazuli.`);
    return current;
  }

  // Conservative estimate of lapis drops per ore block (to compute blocks to mine)
  const estimatedYieldPerBlock = 4;

  let attempts = 0;
  while (attempts < maxAttempts && current < targetTotal) {
    attempts++;
    const need = targetTotal - current;
    bot.chat(`Attempt ${attempts}/${maxAttempts}: need ${need} more lapis.`);

    // First check nearby within 32 blocks
    let oreBlock = findNearbyLapisOre();
    if (!oreBlock) {
      bot.chat(`No lapis ore within 32 blocks. Exploring downward for up to ${exploreTime}s...`);
      try {
        const found = await exploreUntil(bot, new Vec3(0, -1, 0), exploreTime, () => {
          return findNearbyLapisOre() || null;
        });
        if (found) {
          // exploreUntil's callback returned a Block from findNearbyLapisOre(); re-run to get the real block object
          oreBlock = findNearbyLapisOre();
        } else {
          bot.chat('Exploration did not find lapis ore this attempt.');
        }
      } catch (err) {
        bot.chat(`Exploration error: ${err.message}`);
      }
    }

    if (!oreBlock) {
      bot.chat(`No lapis ore found this attempt.`);
      // small delay before next attempt
      await bot.waitForTicks(10);
      current = getItemCountByName('lapis_lazuli');
      continue;
    }

    bot.chat(`Found ${oreBlock.name} at ${oreBlock.position}. Moving there...`);
    try {
      await moveNearBlock(oreBlock);
    } catch (err) {
      bot.chat(`Failed to move near lapis ore: ${err.message}`);
      // Try next attempt
      await bot.waitForTicks(10);
      current = getItemCountByName('lapis_lazuli');
      continue;
    }

    // Compute how many ore blocks to mine (blocks, not items)
    const blocksToMine = Math.max(1, Math.ceil((need) / estimatedYieldPerBlock));
    bot.chat(`Mining up to ${blocksToMine} ${oreBlock.name} block(s) to get lapis...`);

    try {
      const gained = await mineBlock(bot, oreBlock.name, blocksToMine);
      // wait for inventory sync
      await bot.waitForTicks(4);
      current = getItemCountByName('lapis_lazuli');
      bot.chat(`Mining attempt gained ${gained} lapis (now have ${current}/${targetTotal}).`);
      // loop will check condition again
    } catch (err) {
      bot.chat(`Mining failed: ${err.message}`);
      // wait a bit and retry
      await bot.waitForTicks(10);
      current = getItemCountByName('lapis_lazuli');
    }
  }

  current = getItemCountByName('lapis_lazuli');
  if (current >= targetTotal) {
    bot.chat(`Success: have ${current}/${targetTotal} lapis_lazuli.`);
    return current;
  } else {
    const msg = `Failed to obtain ${targetTotal} lapis_lazuli after ${attempts} attempts. Currently have ${current}.`;
    bot.chat(msg);
    throw new Error(msg);
  }
}
